# -*- coding: utf-8 -*-
CURATOR_HTML_CONTENT = '<!DOCTYPE html>\n<html lang="vi">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Biên Tập Viên Rổ Hàng - Khang Ngô Nhà Phố</title>\n    <!-- Google Fonts: Outfit & Inter -->\n    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=Outfit:wght@400;500;600;700;800&display=swap" rel="stylesheet">\n    <style>\n        :root {\n            --bg-color: #0b0f19;\n            --panel-bg: rgba(22, 28, 45, 0.7);\n            --card-bg: rgba(30, 41, 59, 0.6);\n            --border-color: rgba(148, 163, 184, 0.15);\n            --text-main: #f8fafc;\n            --text-muted: #94a3b8;\n            \n            /* Accents */\n            --accent-gold: #fbbf24;\n            --accent-red: #ef4444;\n            --accent-green: #10b981;\n            --accent-blue: #3b82f6;\n            --accent-cyan: #06b6d4;\n            --accent-slate: #64748b;\n            \n            /* Shadows & Blur */\n            --shadow-premium: 0 8px 32px 0 rgba(0, 0, 0, 0.37);\n            --glass-blur: blur(12px);\n        }\n\n        * {\n            margin: 0;\n            padding: 0;\n            box-sizing: border-box;\n            font-family: \'Inter\', sans-serif;\n            scroll-behavior: smooth;\n        }\n\n        body {\n            background-color: var(--bg-color);\n            color: var(--text-main);\n            height: 100vh;\n            overflow: hidden;\n            display: flex;\n            flex-direction: column;\n            background-image: radial-gradient(circle at 10% 20%, rgba(26, 32, 60, 0.5) 0%, rgba(10, 12, 25, 0.5) 90%);\n        }\n\n        /* Top Header */\n        header {\n            height: 70px;\n            background: rgba(15, 23, 42, 0.9);\n            backdrop-filter: var(--glass-blur);\n            border-bottom: 1px solid var(--border-color);\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            padding: 0 30px;\n            z-index: 100;\n        }\n\n        .logo-section {\n            display: flex;\n            align-items: center;\n            gap: 15px;\n        }\n\n        .logo-section h1 {\n            font-family: \'Outfit\', sans-serif;\n            font-size: 22px;\n            font-weight: 800;\n            background: linear-gradient(135deg, var(--accent-gold) 0%, #f59e0b 100%);\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n            letter-spacing: 0.5px;\n        }\n\n        .logo-section span {\n            font-size: 11px;\n            text-transform: uppercase;\n            letter-spacing: 2px;\n            color: var(--text-muted);\n            border: 1px solid var(--border-color);\n            padding: 3px 8px;\n            border-radius: 4px;\n            background: rgba(255, 255, 255, 0.03);\n        }\n\n        .status-widgets {\n            display: flex;\n            align-items: center;\n            gap: 20px;\n        }\n\n        .widget-item {\n            font-size: 13px;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n            background: rgba(30, 41, 59, 0.8);\n            padding: 6px 12px;\n            border-radius: 8px;\n            border: 1px solid var(--border-color);\n        }\n\n        .dot-indicator {\n            width: 8px;\n            height: 8px;\n            border-radius: 50%;\n            display: inline-block;\n        }\n\n        .dot-green { background-color: var(--accent-green); box-shadow: 0 0 8px var(--accent-green); }\n        .dot-yellow { background-color: var(--accent-gold); box-shadow: 0 0 8px var(--accent-gold); }\n        .dot-red { background-color: var(--accent-red); box-shadow: 0 0 8px var(--accent-red); }\n\n        /* Main Layout */\n        .workspace {\n            flex: 1;\n            display: flex;\n            overflow: hidden;\n            height: calc(100vh - 70px);\n        }\n\n        /* Sidebar: List */\n        .sidebar {\n            width: 380px;\n            border-right: 1px solid var(--border-color);\n            background: var(--panel-bg);\n            backdrop-filter: var(--glass-blur);\n            display: flex;\n            flex-direction: column;\n            overflow: hidden;\n        }\n\n        .search-box {\n            padding: 15px;\n            border-bottom: 1px solid var(--border-color);\n        }\n\n        .search-box input {\n            width: 100%;\n            padding: 10px 15px;\n            background: rgba(15, 23, 42, 0.6);\n            border: 1px solid var(--border-color);\n            border-radius: 8px;\n            color: var(--text-main);\n            font-size: 14px;\n            outline: none;\n            transition: 0.3s;\n        }\n\n        .search-box input:focus {\n            border-color: var(--accent-gold);\n            box-shadow: 0 0 10px rgba(251, 191, 36, 0.15);\n        }\n\n        .sidebar-tabs {\n            display: flex;\n            border-bottom: 1px solid var(--border-color);\n            background: rgba(15, 23, 42, 0.3);\n        }\n\n        .sidebar-tab {\n            flex: 1;\n            padding: 12px 4px;\n            text-align: center;\n            font-size: 11px;\n            font-weight: 600;\n            color: var(--text-muted);\n            cursor: pointer;\n            transition: 0.2s;\n            border-bottom: 2px solid transparent;\n            word-break: break-word;\n        }\n\n        .sidebar-tab:hover {\n            color: var(--text-main);\n        }\n\n        .sidebar-tab.active {\n            color: var(--accent-gold);\n            border-bottom-color: var(--accent-gold);\n            background: rgba(30, 41, 59, 0.2);\n        }\n\n        .listing-scroll {\n            flex: 1;\n            overflow-y: auto;\n            padding: 10px;\n        }\n\n        .listing-scroll::-webkit-scrollbar {\n            width: 6px;\n        }\n\n        .listing-scroll::-webkit-scrollbar-thumb {\n            background-color: var(--border-color);\n            border-radius: 3px;\n        }\n\n        .house-card {\n            background: var(--card-bg);\n            border: 1px solid var(--border-color);\n            border-radius: 12px;\n            padding: 12px;\n            margin-bottom: 10px;\n            cursor: pointer;\n            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n            position: relative;\n            overflow: hidden;\n        }\n\n        .house-card::before {\n            content: \'\';\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 4px;\n            height: 100%;\n            background: transparent;\n            transition: 0.2s;\n        }\n\n        .house-card:hover {\n            transform: translateY(-2px);\n            background: rgba(30, 41, 59, 0.9);\n            border-color: rgba(251, 191, 36, 0.4);\n            box-shadow: var(--shadow-premium);\n        }\n\n        .house-card.active {\n            background: rgba(24, 37, 66, 0.9);\n            border-color: var(--accent-gold);\n            box-shadow: 0 4px 20px rgba(251, 191, 36, 0.08);\n        }\n\n        .house-card.active::before {\n            background: var(--accent-gold);\n        }\n\n        .house-card-header {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            margin-bottom: 8px;\n        }\n\n        .house-id {\n            font-size: 13px;\n            font-weight: 700;\n            color: var(--text-main);\n            font-family: \'Outfit\', sans-serif;\n        }\n\n        .status-badge {\n            font-size: 10px;\n            padding: 2px 6px;\n            border-radius: 4px;\n            font-weight: 700;\n            text-transform: uppercase;\n        }\n\n        .badge-raw_text { background: rgba(239, 68, 68, 0.15); color: var(--accent-red); border: 1px solid rgba(239, 68, 68, 0.3); }\n        .badge-raw_complete { background: rgba(59, 82, 246, 0.15); color: var(--accent-blue); border: 1px solid rgba(59, 82, 246, 0.3); }\n        .badge-published { background: rgba(16, 185, 129, 0.15); color: var(--accent-green); border: 1px solid rgba(16, 185, 129, 0.3); }\n        .badge-crawl_failed { background: rgba(239, 68, 68, 0.15); color: var(--accent-red); border: 1px solid rgba(239, 68, 68, 0.3); }\n\n        .house-title {\n            font-size: 13px;\n            line-height: 1.4;\n            color: var(--text-muted);\n            margin-bottom: 8px;\n            display: -webkit-box;\n            -webkit-line-clamp: 2;\n            -webkit-box-orient: vertical;\n            overflow: hidden;\n        }\n\n        .house-meta {\n            display: flex;\n            gap: 12px;\n            font-size: 11px;\n            color: var(--text-muted);\n        }\n\n        .house-meta span {\n            display: flex;\n            align-items: center;\n            gap: 4px;\n        }\n\n        /* Detail Panel */\n        .detail-panel {\n            flex: 1;\n            display: flex;\n            flex-direction: column;\n            overflow: hidden;\n            background: rgba(15, 23, 42, 0.4);\n        }\n\n        /* Mode Selector Tab */\n        .mode-tabs {\n            display: flex;\n            gap: 10px;\n            padding: 15px 30px;\n            border-bottom: 1px solid var(--border-color);\n            background: rgba(15, 23, 42, 0.6);\n        }\n\n        .mode-tab {\n            padding: 10px 20px;\n            border-radius: 8px;\n            font-size: 13px;\n            font-weight: 600;\n            color: var(--text-muted);\n            cursor: pointer;\n            transition: 0.3s;\n            border: 1px solid transparent;\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n\n        .mode-tab:hover {\n            color: var(--text-main);\n            background: rgba(255, 255, 255, 0.02);\n        }\n\n        .mode-tab.active {\n            color: var(--accent-gold);\n            background: rgba(251, 191, 36, 0.08);\n            border-color: rgba(251, 191, 36, 0.25);\n        }\n\n        /* Content Sections */\n        .content-section {\n            display: none;\n            flex: 1;\n            overflow-y: auto;\n            padding: 30px;\n        }\n\n        .content-section.active {\n            display: block;\n        }\n\n        /* 1. CRAWL TAB */\n        .panel-row {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 20px;\n            margin-bottom: 25px;\n        }\n\n        .panel-card {\n            background: var(--panel-bg);\n            border: 1px solid var(--border-color);\n            border-radius: 16px;\n            padding: 20px;\n            backdrop-filter: var(--glass-blur);\n        }\n\n        .panel-title {\n            font-family: \'Outfit\', sans-serif;\n            font-size: 16px;\n            font-weight: 700;\n            margin-bottom: 15px;\n            color: var(--accent-gold);\n            display: flex;\n            align-items: center;\n            gap: 10px;\n        }\n\n        .form-group {\n            margin-bottom: 15px;\n        }\n\n        .form-group label {\n            display: block;\n            font-size: 12px;\n            font-weight: 600;\n            color: var(--text-muted);\n            margin-bottom: 6px;\n            text-transform: uppercase;\n        }\n\n        .form-group input, .form-group select, .form-group textarea {\n            width: 100%;\n            padding: 10px 14px;\n            background: rgba(15, 23, 42, 0.6);\n            border: 1px solid var(--border-color);\n            border-radius: 8px;\n            color: var(--text-main);\n            font-size: 14px;\n            outline: none;\n            transition: 0.3s;\n        }\n\n        .form-group input:focus, .form-group select:focus, .form-group textarea:focus {\n            border-color: var(--accent-gold);\n        }\n\n        .btn {\n            display: inline-flex;\n            align-items: center;\n            justify-content: center;\n            gap: 8px;\n            padding: 12px 24px;\n            border-radius: 8px;\n            font-size: 14px;\n            font-weight: 700;\n            cursor: pointer;\n            transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n            border: none;\n            outline: none;\n        }\n\n        .btn-gold {\n            background: linear-gradient(135deg, var(--accent-gold) 0%, #d97706 100%);\n            color: #0b0f19;\n            box-shadow: 0 4px 15px rgba(251, 191, 36, 0.25);\n        }\n\n        .btn-gold:hover {\n            transform: translateY(-1px);\n            box-shadow: 0 6px 20px rgba(251, 191, 36, 0.35);\n        }\n\n        .btn-green {\n            background: linear-gradient(135deg, var(--accent-green) 0%, #047857 100%);\n            color: white;\n            box-shadow: 0 4px 15px rgba(16, 185, 129, 0.25);\n        }\n\n        .btn-green:hover {\n            transform: translateY(-1px);\n            box-shadow: 0 6px 20px rgba(16, 185, 129, 0.35);\n        }\n\n        .btn-outline {\n            background: transparent;\n            border: 1px solid var(--border-color);\n            color: var(--text-main);\n        }\n\n        .btn-outline:hover {\n            background: rgba(255, 255, 255, 0.05);\n            border-color: var(--text-muted);\n        }\n\n        /* Terminal Console */\n        .terminal-container {\n            margin-top: 20px;\n            background: #05070c;\n            border: 1px solid var(--border-color);\n            border-radius: 12px;\n            height: 380px;\n            display: flex;\n            flex-direction: column;\n            overflow: hidden;\n            box-shadow: inset 0 0 20px rgba(0,0,0,0.8);\n        }\n\n        .terminal-header {\n            background: #111827;\n            padding: 8px 15px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            border-bottom: 1px solid var(--border-color);\n        }\n\n        .terminal-dots {\n            display: flex;\n            gap: 6px;\n        }\n\n        .terminal-dot {\n            width: 10px;\n            height: 10px;\n            border-radius: 50%;\n        }\n\n        .terminal-body {\n            flex: 1;\n            padding: 15px;\n            overflow-y: auto;\n            font-family: \'Courier New\', Courier, monospace;\n            font-size: 13px;\n            line-height: 1.5;\n            color: #38bdf8;\n            text-shadow: 0 0 2px rgba(56, 189, 248, 0.2);\n        }\n\n        .terminal-line {\n            margin-bottom: 5px;\n            white-space: pre-wrap;\n        }\n\n        /* Image Station */\n        .image-station {\n            margin-bottom: 25px;\n        }\n\n        .image-grid {\n            display: grid;\n            grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));\n            gap: 15px;\n            margin-top: 15px;\n        }\n\n        .image-card {\n            background: var(--card-bg);\n            border: 1px solid var(--border-color);\n            border-radius: 12px;\n            overflow: hidden;\n            position: relative;\n            transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n            display: flex;\n            flex-direction: column;\n        }\n\n        .image-card:hover {\n            transform: translateY(-2px);\n            border-color: rgba(255, 255, 255, 0.1);\n        }\n\n        .image-wrapper {\n            position: relative;\n            padding-top: 68%;\n            background: #000;\n            overflow: hidden;\n        }\n\n        .image-wrapper img {\n            position: absolute;\n            top: 0;\n            left: 0;\n            width: 100%;\n            height: 100%;\n            object-fit: cover;\n            transition: 0.3s;\n        }\n\n        .image-card:hover .image-wrapper img {\n            transform: scale(1.05);\n        }\n\n        .image-role-badge {\n            position: absolute;\n            top: 8px;\n            left: 8px;\n            padding: 3px 8px;\n            font-size: 10px;\n            font-weight: 700;\n            border-radius: 4px;\n            text-transform: uppercase;\n            box-shadow: 0 2px 8px rgba(0,0,0,0.5);\n        }\n\n        .image-controls {\n            padding: 8px;\n            background: rgba(15, 23, 42, 0.6);\n            display: flex;\n            flex-direction: column;\n            gap: 6px;\n            border-top: 1px solid var(--border-color);\n        }\n\n        .role-btn-group {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 4px;\n        }\n\n        .role-btn {\n            font-size: 10px;\n            font-weight: 700;\n            padding: 4px 2px;\n            text-align: center;\n            border-radius: 4px;\n            cursor: pointer;\n            transition: 0.2s;\n            background: rgba(255, 255, 255, 0.05);\n            border: 1px solid rgba(255, 255, 255, 0.05);\n            color: var(--text-muted);\n        }\n\n        .role-btn:hover {\n            background: rgba(255, 255, 255, 0.1);\n            color: var(--text-main);\n        }\n\n        /* Role Active styling */\n        .role-bia.active { background: rgba(16, 185, 129, 0.2); border-color: var(--accent-green); color: var(--accent-green); }\n        .role-mt.active { background: rgba(239, 68, 68, 0.2); border-color: var(--accent-red); color: var(--accent-red); }\n        .role-sodo.active { background: rgba(251, 191, 36, 0.2); border-color: var(--accent-gold); color: var(--accent-gold); }\n        .role-hem.active { background: rgba(59, 130, 246, 0.2); border-color: var(--accent-blue); color: var(--accent-blue); }\n        .role-public.active { background: rgba(6, 182, 212, 0.2); border-color: var(--accent-cyan); color: var(--accent-cyan); }\n        .role-an.active { background: rgba(100, 116, 139, 0.2); border-color: var(--accent-slate); color: var(--accent-slate); }\n\n        .order-btn-group {\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n            margin-top: 2px;\n        }\n\n        .order-btn {\n            font-size: 12px;\n            background: transparent;\n            border: none;\n            color: var(--text-muted);\n            cursor: pointer;\n            padding: 2px 6px;\n            border-radius: 4px;\n            transition: 0.2s;\n        }\n\n        .order-btn:hover {\n            color: var(--text-main);\n            background: rgba(255,255,255,0.05);\n        }\n\n        /* 3. EDITOR VIEW */\n        .editor-container {\n            display: grid;\n            grid-template-columns: 2fr 1fr;\n            gap: 20px;\n        }\n\n        .editor-form {\n            display: flex;\n            flex-direction: column;\n            gap: 20px;\n        }\n\n        .editor-grid-3 {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 15px;\n        }\n\n        .editor-grid-2 {\n            display: grid;\n            grid-template-columns: 1fr 1fr;\n            gap: 15px;\n        }\n\n        /* Modal */\n        .modal-overlay {\n            position: fixed;\n            top: 0;\n            left: 0;\n            width: 100vw;\n            height: 100vh;\n            background: rgba(5, 7, 12, 0.85);\n            backdrop-filter: blur(10px);\n            z-index: 1000;\n            display: none;\n            align-items: center;\n            justify-content: center;\n            padding: 20px;\n        }\n\n        .modal-box {\n            background: var(--panel-bg);\n            border: 1px solid var(--accent-gold);\n            border-radius: 20px;\n            width: 100%;\n            max-width: 800px;\n            max-height: 90vh;\n            overflow-y: auto;\n            padding: 30px;\n            box-shadow: 0 0 30px rgba(251, 191, 36, 0.2);\n            position: relative;\n        }\n\n        .modal-title {\n            font-family: \'Outfit\', sans-serif;\n            font-size: 20px;\n            font-weight: 800;\n            color: var(--accent-gold);\n            margin-bottom: 20px;\n            display: flex;\n            justify-content: space-between;\n            align-items: center;\n        }\n\n        .modal-close {\n            cursor: pointer;\n            font-size: 24px;\n            color: var(--text-muted);\n            transition: 0.2s;\n        }\n\n        .modal-close:hover {\n            color: var(--text-main);\n        }\n\n        .raw-data-textarea {\n            width: 100%;\n            height: 250px;\n            background: #05070c;\n            border: 1px solid var(--border-color);\n            border-radius: 10px;\n            color: #38bdf8;\n            font-family: monospace;\n            font-size: 12px;\n            padding: 15px;\n            resize: none;\n            outline: none;\n            margin-bottom: 20px;\n        }\n\n        /* Progress Bar */\n        .progress-bar-wrapper {\n            margin-top: 15px;\n            width: 100%;\n            height: 12px;\n            background: rgba(15, 23, 42, 0.8);\n            border: 1px solid var(--border-color);\n            border-radius: 6px;\n            overflow: hidden;\n        }\n\n        .progress-bar-fill {\n            height: 100%;\n            background: linear-gradient(90deg, var(--accent-gold) 0%, var(--accent-green) 100%);\n            width: 0%;\n            transition: width 0.4s ease;\n        }\n\n        /* Dropdown custom */\n        .alert-box {\n            background: rgba(251, 191, 36, 0.08);\n            border: 1px solid rgba(251, 191, 36, 0.2);\n            border-radius: 8px;\n            padding: 12px 15px;\n            font-size: 13px;\n            line-height: 1.5;\n            color: var(--accent-gold);\n            margin-bottom: 15px;\n            display: flex;\n            gap: 10px;\n            align-items: flex-start;\n        }\n\n        .alert-box svg {\n            flex-shrink: 0;\n            margin-top: 2px;\n        }\n\n        /* CSS for prompt-cache cookie dialog on frontend */\n        .cookie-modal-inner {\n            display: flex;\n            flex-direction: column;\n            gap: 15px;\n        }\n\n        /* Toast Notifications Container */\n        #toast-container {\n            position: fixed;\n            top: 25px;\n            right: 25px;\n            z-index: 10000;\n            display: flex;\n            flex-direction: column;\n            gap: 12px;\n            pointer-events: none;\n        }\n        \n        .toast-item {\n            pointer-events: auto;\n            background: rgba(11, 15, 25, 0.95);\n            border: 1px solid rgba(148, 163, 184, 0.25);\n            backdrop-filter: blur(16px);\n            padding: 14px 22px;\n            border-radius: 10px;\n            color: #f8fafc;\n            font-size: 14px;\n            font-weight: 600;\n            box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6);\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            transform: translateX(130%);\n            transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275), opacity 0.3s;\n            opacity: 0;\n            min-width: 320px;\n            max-width: 450px;\n        }\n        \n        .toast-item.show {\n            transform: translateX(0);\n            opacity: 1;\n        }\n        \n        .toast-success {\n            border-left: 5px solid var(--accent-green);\n            box-shadow: 0 8px 30px rgba(16, 185, 129, 0.15), 0 12px 40px rgba(0, 0, 0, 0.6);\n        }\n        \n        .toast-warning {\n            border-left: 5px solid var(--accent-gold);\n            box-shadow: 0 8px 30px rgba(251, 191, 36, 0.15), 0 12px 40px rgba(0, 0, 0, 0.6);\n        }\n        \n        .toast-error {\n            border-left: 5px solid var(--accent-red);\n            box-shadow: 0 8px 30px rgba(239, 68, 68, 0.15), 0 12px 40px rgba(0, 0, 0, 0.6);\n        }\n\n        @keyframes spin {\n            to { transform: rotate(360deg); }\n        }\n        .spinner-small {\n            display: inline-block;\n            width: 14px;\n            height: 14px;\n            border: 2px solid white;\n            border-top: 2px solid transparent;\n            border-radius: 50%;\n            animation: spin 0.8s linear infinite;\n        }\n\n    </style>\n</head>\n<body>\n\n    <!-- Premium Toast Notifications Container -->\n    <div id="toast-container"></div>\n\n    <!-- Top Header -->\n    <header>\n        <div class="logo-section">\n            <h1>KHANG NGÔ NHÀ PHỐ</h1>\n            <span>Curator Dashboard</span>\n        </div>\n        <div class="status-widgets">\n            <div class="widget-item">\n                <span class="dot-indicator dot-green" id="db-indicator"></span>\n                <span>SQLite Database: <strong>raw_archive.db</strong></span>\n            </div>\n            <div class="widget-item">\n                <span class="dot-indicator dot-green" id="cookie-indicator"></span>\n                <span>Cookie Thiên Khôi: <strong id="cookie-status">Hoạt động</strong></span>\n            </div>\n        </div>\n    </header>\n\n    <!-- Workspace -->\n    <div class="workspace">\n\n        <!-- Sidebar: List of Houses -->\n        <div class="sidebar">\n            <div class="search-box" style="position: relative;">\n                <input type="text" id="sidebar-search" placeholder="Tìm theo Mã căn, Quận, Đường..." oninput="fetchListings()" style="margin-bottom: 10px; padding-right: 35px;">\n                <div id="search-spinner" class="spinner-small" style="display: none; position: absolute; right: 25px; top: 25px; border-color: var(--accent-gold); border-top-color: transparent;"></div>\n                <div style="display: flex; gap: 8px;">\n                    <input type="text" id="filter-quan" placeholder="Quận (VD: 3, 10)" oninput="fetchListings()" style="flex: 1; padding: 8px 10px; font-size: 12px; border-radius: 6px; background: rgba(15, 23, 42, 0.6); border: 1px solid var(--border-color); color: var(--text-main); outline: none;">\n                    <input type="text" id="filter-duong" placeholder="Đường (VD: Lê Văn Sỹ)" oninput="fetchListings()" style="flex: 1.5; padding: 8px 10px; font-size: 12px; border-radius: 6px; background: rgba(15, 23, 42, 0.6); border: 1px solid var(--border-color); color: var(--text-main); outline: none;">\n                    <input type="text" id="filter-sonha" placeholder="Số nhà (VD: 120)" oninput="fetchListings()" style="flex: 1; padding: 8px 10px; font-size: 12px; border-radius: 6px; background: rgba(15, 23, 42, 0.6); border: 1px solid var(--border-color); color: var(--text-main); outline: none;">\n                </div>\n            </div>\n            <div class="sidebar-tabs">\n                <div class="sidebar-tab active" data-status="raw_text" onclick="setSidebarStatus(\'raw_text\')">Chờ di cư ảnh</div>\n                <div class="sidebar-tab" data-status="raw_complete" onclick="setSidebarStatus(\'raw_complete\')">Chờ biên tập</div>\n                <div class="sidebar-tab" data-status="published" onclick="setSidebarStatus(\'published\')">Đã xuất bản</div>\n                <div class="sidebar-tab" data-status="missing_raw_json" onclick="setSidebarStatus(\'missing_raw_json\')">Thiếu JSON</div>\n                <div class="sidebar-tab" data-status="crawl_failed" onclick="setSidebarStatus(\'crawl_failed\')" style="border-left: 1px solid var(--border-color); color: #f87171;">Lỗi cào</div>\n            </div>\n            <!-- Khung chọn lọc đẩy thô Pool hàng loạt (US-040) -->\n            <div class="sidebar-actions" id="sidebar-bulk-actions" style="display: none; padding: 10px 12px; background: rgba(251, 191, 36, 0.05); border-bottom: 1px solid var(--border-color); display: flex; justify-content: space-between; align-items: center; gap: 8px;">\n                <label style="font-size: 11px; color: var(--text-muted); cursor: pointer; display: flex; align-items: center; gap: 6px; user-select: none;">\n                    <input type="checkbox" id="chk-select-all-filtered" onclick="toggleSelectAllFiltered(this)" style="cursor: pointer; width: 14px; height: 14px;">\n                    <span>Chọn tất cả</span>\n                </label>\n                <button class="btn btn-gold" id="btn-bulk-publish" onclick="bulkPublishSelected()" style="font-size: 11px; padding: 5px 12px; border-radius: 6px; height: auto; font-family: \'Outfit\', sans-serif; font-weight: bold; background: linear-gradient(135deg, var(--accent-gold) 0%, #d97706 100%); border: none; box-shadow: 0 4px 10px rgba(245, 158, 11, 0.2);">⚡ ĐẨY POOL (<span id="bulk-select-count">0</span>)</button>\n            </div>\n            <div class="listing-scroll" id="listings-list">\n                <!-- House cards will render dynamically here -->\n            </div>\n        </div>\n\n        <!-- Detail & Operations Panel -->\n        <div class="detail-panel">\n            <div class="mode-tabs">\n                <div class="mode-tab active" data-tab="crawl-tab" onclick="switchTab(\'crawl-tab\')">\n                    ⚡ Bắt đầu Cào tin\n                </div>\n                <div class="mode-tab" data-tab="migrate-tab" onclick="switchTab(\'migrate-tab\')">\n                    🖼️ Di cư hình ảnh\n                </div>\n                <div class="mode-tab" data-tab="edit-tab" id="curate-tab-trigger" onclick="switchTab(\'edit-tab\')">\n                    ✍️ Biên tập & Xuất bản\n                </div>\n                <div class="mode-tab" data-tab="history-tab" onclick="switchTab(\'history-tab\')">\n                    📊 Lịch sử cào\n                </div>\n            </div>\n\n            <!-- TAB 1: CRAWL SYSTEM -->\n            <div class="content-section active" id="crawl-tab">\n                <div class="panel-row">\n                    <div style="display: flex; flex-direction: column; gap: 20px;">\n                        <div class="panel-card">\n                            <div class="panel-title">📡 Stealth Crawler Controller</div>\n                            \n                            <div class="form-group">\n                                <label>1. URL DANH SÁCH QUẬN THIÊN KHÔI</label>\n                                <input type="text" id="crawl-url" placeholder="https://data.thienkhoi.com/Hang/List?Page=1&pID_Quan=..." value="">\n                            </div>\n\n                            <div class="panel-row" style="margin-bottom: 12px; grid-template-columns: 1.5fr 1fr;">\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label>⚡ CHỌN NHANH TỐC ĐỘ CÀO TIN (PRESET)</label>\n                                    <select id="crawl-speed-preset" onchange="onSpeedPresetChange(this.value)">\n                                        <option value="safe">🟢 An toàn (Stealth Mode) - Nghỉ 8-15s / 20-40s</option>\n                                        <option value="optimal" selected>🟡 Tối ưu (Fast & Safe) - Nghỉ 3-6s / 5-10s</option>\n                                        <option value="turbo">🔴 Siêu tốc (Turbo Mode) - Nghỉ 1.5-3s / 3-5s</option>\n                                        <option value="custom">⚙️ Tùy chỉnh (Độ trễ do bạn tự đặt bên phải)</option>\n                                    </select>\n                                </div>\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label>2. TÊN QUẬN MỤC TIÊU (LỌC TRƯỚC)</label>\n                                    <select id="crawl-district">\n                                        <option value="" selected>Tất cả (Không lọc quận)</option>\n                                        <option value="Quận 1">Quận 1</option>\n                                        <option value="Quận 3">Quận 3</option>\n                                        <option value="Quận 4">Quận 4</option>\n                                        <option value="Quận 5">Quận 5</option>\n                                        <option value="Quận 6">Quận 6</option>\n                                        <option value="Quận 7">Quận 7</option>\n                                        <option value="Quận 8">Quận 8</option>\n                                        <option value="Quận 10">Quận 10</option>\n                                        <option value="Quận 11">Quận 11</option>\n                                        <option value="Quận 12">Quận 12</option>\n                                        <option value="Bình Thạnh">Bình Thạnh</option>\n                                        <option value="Phú Nhuận">Phú Nhuận</option>\n                                        <option value="Gò Vấp">Gò Vấp</option>\n                                        <option value="Tân Bình">Tân Bình</option>\n                                        <option value="Tân Phú">Tân Phú</option>\n                                        <option value="Bình Tân">Bình Tân</option>\n                                        <option value="Thủ Đức">Thủ Đức</option>\n                                        <option value="Hóc Môn">Hóc Môn</option>\n                                        <option value="Nhà Bè">Nhà Bè</option>\n                                        <option value="Bình Chánh">Bình Chánh</option>\n                                        <option value="Củ Chi">Củ Chi</option>\n                                        <option value="Cần Giờ">Cần Giờ</option>\n                                    </select>\n                                </div>\n                            </div>\n\n                            <div class="panel-row" style="margin-bottom: 0; grid-template-columns: 1fr 1fr;">\n                                <div class="form-group">\n                                    <label>3. GIỚI HẠN CĂN <span style="font-size: 0.8em; opacity: 0.7;">(Để trống/0 để cào không giới hạn)</span></label>\n                                    <input type="number" id="crawl-limit" value="5" min="0" placeholder="Không giới hạn">\n                                </div>\n                                <div class="form-group">\n                                    <label>4. TRANG BẮT ĐẦU</label>\n                                    <input type="number" id="crawl-start-page" value="1" min="1">\n                                </div>\n                            </div>\n\n                            <div class="alert-box" id="speed-preset-alert">\n                                <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">\n                                    <path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/>\n                                </svg>\n                                <div id="speed-preset-alert-text">\n                                    <strong>🟡 Chế độ Tối ưu (Fast & Safe) đang bật:</strong> Nghỉ ngẫu nhiên 3 - 6 giây giữa các căn và 5 - 10 giây khi chuyển trang. Tăng tốc độ cào ~2.5 lần nhưng vẫn bảo đảm an toàn chống chặn Cookie.\n                                </div>\n                            </div>\n\n                            <div style="display: flex; flex-wrap: wrap; gap: 10px;">\n                                <button class="btn btn-gold" id="btn-start-crawl" onclick="startCrawl()">👉 BẮT ĐẦU CÀO TIN</button>\n                                <button class="btn btn-outline" onclick="openCookieModal()">🔑 Cập nhật Cookie</button>\n                                <button class="btn" style="background: linear-gradient(135deg, var(--accent-red) 0%, #b91c1c 100%); color: white; box-shadow: 0 4px 15px rgba(239, 68, 68, 0.25);" onclick="clearAllListings()">🧹 Xóa Sạch Dữ Liệu Cũ</button>\n                            </div>\n                        </div>\n\n                        <!-- Userscript Installation Card -->\n                        <div class="panel-card" style="border-left: 4px solid var(--accent-gold);">\n                            <div class="panel-title">🔌 Tiện ích trình duyệt (Tampermonkey Scraper)</div>\n                            <p style="font-size: 13px; color: var(--text-muted); line-height: 1.5; margin-bottom: 12px;">\n                                Cài đặt tiện ích mở rộng (Userscript) chạy trực tiếp trên website Thiên Khôi để cào nhanh lẻ hoặc cào hàng loạt chỉ với 1-click từ trang danh sách đã lọc.\n                            </p>\n                            <a href="static/js/thienkhoi_list_scraper.user.js" target="_blank" class="btn btn-outline" style="border-color: var(--accent-gold); color: var(--accent-gold); display: inline-flex; align-items: center; justify-content: center; gap: 8px; width: fit-content; text-decoration: none;">\n                                ⚡ CÀI ĐẶT / CẬP NHẬT SCARPER SCRIPT\n                            </a>\n                        </div>\n                    </div>\n\n                    <div class="panel-card" style="display: flex; flex-direction: column;">\n                        <div class="panel-title">📋 Cấu hình Hệ thống & API</div>\n                        <div class="form-group">\n                            <label>ID GOOGLE SHEETS POOL</label>\n                            <input type="text" id="cfg-sheet-id" value="">\n                        </div>\n                        <div class="form-group">\n                            <label>ID THƯ MỤC GOOGLE DRIVE 5TB</label>\n                            <input type="text" id="cfg-drive-folder" placeholder="Nhập Folder ID để upload ảnh..." value="">\n                        </div>\n                        <!-- Ẩn OpenAI API Key trên giao diện theo yêu cầu (đọc cố định từ cấu hình hệ thống) -->\n                        <div style="display: none;">\n                            <div class="form-group">\n                                <label>🔑 OPENAI API KEY</label>\n                                <input type="password" id="cfg-openai-key" placeholder="sk-proj-..." value="">\n                            </div>\n                        </div>\n                        <div class="form-group">\n                            <label>🤖 OPENAI SYSTEM PROMPT (LUẬT THÉP VÀ CẤU TRÚC AI BIÊN TẬP)</label>\n                            <textarea id="cfg-openai-prompt" rows="8" style="resize: vertical; font-family: monospace; font-size: 11px; color: var(--text-main); background: rgba(0,0,0,0.2); border: 1px solid var(--border-color); border-radius: 6px; padding: 8px;" placeholder="Nhập System Prompt..."></textarea>\n                        </div>\n                        \n                        <div style="border-top: 1px solid var(--border-color); margin: 15px 0; padding-top: 15px;">\n                            <label style="font-size: 12px; font-weight: 600; color: var(--accent-gold); text-transform: uppercase; margin-bottom: 10px; display: block;">⏱️ Tùy chỉnh Độ trễ Cào tin (Giây)</label>\n                            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 10px;">\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 10px;">Nghỉ Căn Min (s)</label>\n                                    <input type="number" step="0.1" id="cfg-delay-house-min" value="3.0" oninput="detectAndSetPresetDropdown()">\n                                </div>\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 10px;">Nghỉ Căn Max (s)</label>\n                                    <input type="number" step="0.1" id="cfg-delay-house-max" value="6.0" oninput="detectAndSetPresetDropdown()">\n                                </div>\n                            </div>\n                            <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 15px;">\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 10px;">Nghỉ Trang Min (s)</label>\n                                    <input type="number" step="0.1" id="cfg-delay-page-min" value="5.0" oninput="detectAndSetPresetDropdown()">\n                                </div>\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 10px;">Nghỉ Trang Max (s)</label>\n                                    <input type="number" step="0.1" id="cfg-delay-page-max" value="10.0" oninput="detectAndSetPresetDropdown()">\n                                </div>\n                            </div>\n                        </div>\n                        \n                        <button class="btn btn-outline" style="align-self: flex-start; width: 100%; margin-top: auto;" onclick="saveConfig()">💾 Lưu Cấu Hình Hệ Thống</button>\n                    </div>\n                </div>\n\n                <!-- Terminal -->\n                <div class="terminal-container">\n                    <div class="terminal-header">\n                        <div class="terminal-dots">\n                            <span class="terminal-dot" style="background:#ef4444;"></span>\n                            <span class="terminal-dot" style="background:#fbbf24;"></span>\n                            <span class="terminal-dot" style="background:#10b981;"></span>\n                        </div>\n                        <div style="font-size: 11px; color: var(--text-muted); font-family: monospace;">crawl_pipeline.log</div>\n                        <button onclick="clearLogs()" style="background:transparent; border:none; color:var(--text-muted); cursor:pointer; font-size:11px; font-family:monospace;">Xóa màn hình</button>\n                    </div>\n                    <div class="terminal-body" id="terminal-log">\n                        <!-- Terminal lines here -->\n                    </div>\n                </div>\n                \n                <!-- panel-row 2 for US-100 -->\n                <div class="panel-row" style="margin-top: 20px;">\n                    <!-- Dynamic Filters config card -->\n                    <div class="panel-card">\n                        <div class="panel-title" style="display: flex; justify-content: space-between; align-items: center;">\n                            <span>⚙️ Cấu hình Bộ lọc JSON Động</span>\n                            <button class="btn btn-gold" onclick="triggerSyncJsonUi()" style="font-size: 11px; padding: 4px 10px; height: auto;">🔄 Đồng bộ JSON UI Hàng loạt</button>\n                        </div>\n                        \n                        <div id="dynamic-filters-list" style="margin-bottom: 15px;">\n                            <!-- Dynamic filters list table -->\n                        </div>\n                        \n                        <div style="border-top: 1px solid var(--border-color); padding-top: 15px;">\n                            <label style="font-size: 11px; font-weight: bold; color: var(--accent-gold); text-transform: uppercase; margin-bottom: 10px; display: block;">➕ Thêm Bộ lọc Mới</label>\n                            <div style="display: grid; grid-template-columns: 1.5fr 1.5fr 1fr; gap: 8px; margin-bottom: 8px;">\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 9px;">Khóa Dữ liệu (JSON Key)</label>\n                                    <input type="text" id="new-filter-field" placeholder="e.g. Criteria_Duong_truoc_nha">\n                                </div>\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 9px;">Nhãn hiển thị (Label)</label>\n                                    <input type="text" id="new-filter-label" placeholder="e.g. Đường trước nhà">\n                                </div>\n                                <div class="form-group" style="margin-bottom: 0;">\n                                    <label style="font-size: 9px;">Loại (Type)</label>\n                                    <select id="new-filter-type">\n                                        <option value="select">Select / Combobox</option>\n                                        <option value="text">Văn bản / Text</option>\n                                    </select>\n                                </div>\n                            </div>\n                            <div class="form-group">\n                                <label style="font-size: 9px;">Danh sách tùy chọn (Phân cách bằng dấu phẩy)</label>\n                                <input type="text" id="new-filter-options" placeholder="Để trống nếu là Text, nhập Options1, Options2... nếu là Select">\n                            </div>\n                            <button class="btn btn-outline" onclick="addNewDynamicFilter()" style="width: 100%;">➕ Thêm Bộ lọc vào Cấu hình</button>\n                        </div>\n                    </div>\n                    \n                    <!-- Troubleshooting card -->\n                    <div class="panel-card" style="display: flex; flex-direction: column;">\n                        <div class="panel-title">⚠️ Khắc phục Sự cố Cào tin (Troubleshooting)</div>\n                        <div style="margin-bottom: 10px; font-size: 12px; color: var(--text-muted);">\n                            Danh sách các căn bị lỗi trong quá trình vá dữ liệu chi tiết từ Thiên Khôi.\n                        </div>\n                        <div style="flex: 1; overflow-y: auto; max-height: 350px; border: 1px solid var(--border-color); border-radius: 6px; background: rgba(0,0,0,0.2);">\n                            <table style="width: 100%; border-collapse: collapse; font-size: 11px;">\n                                <thead>\n                                    <tr style="border-bottom: 1px solid var(--border-color); background: rgba(255,255,255,0.02); text-align: left;">\n                                        <th style="padding: 8px;">Mã căn</th>\n                                        <th style="padding: 8px;">Lý do lỗi</th>\n                                        <th style="padding: 8px; text-align: right;">Hành động</th>\n                                    </tr>\n                                </thead>\n                                <tbody id="trouble-table-body">\n                                    <!-- Render failed listings here -->\n                                </tbody>\n                            </table>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <!-- TAB 2: IMAGE MIGRATION -->\n            <div class="content-section" id="migrate-tab">\n                <div class="panel-card" style="max-width: 700px; margin: 0 auto;">\n                    <div class="panel-title">🖼️ Di cư Hình ảnh lên Google Drive / Cục bộ</div>\n                    <p style="font-size: 14px; color: var(--text-muted); line-height: 1.6; margin-bottom: 20px;">\n                        Luồng này quét cơ sở dữ liệu SQLite raw_archive.db để tìm các căn ở trạng thái thô (status = \'raw_text\'). Sau đó tải tất cả ảnh về, đẩy lên thư mục Google Drive đã cấu hình (hoặc lưu cục bộ nếu không có credentials) và tự động đổi link ảnh thành đường dẫn trực tiếp.\n                    </p>\n                    \n                    <div class="form-group" style="max-width: 200px;">\n                        <label>GIỚI HẠN SỐ CĂN DI CƯ</label>\n                        <input type="number" id="migrate-limit" value="10">\n                    </div>\n\n                    <div class="alert-box">\n                        <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">\n                            <path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/>\n                        </svg>\n                        <div>\n                            <strong>Nghỉ Throttling ngẫu nhiên 3-5 giây mỗi căn</strong> được áp dụng tự động để tránh nghẽn băng thông và bảo vệ địa chỉ IP của bạn trước CDN đối tác.\n                        </div>\n                    </div>\n\n                    <button class="btn btn-gold" style="width: 100%;" onclick="startMigration()">🖼️ BẮT ĐẦU DI CƯ HÌNH ẢNH</button>\n                    \n                    <div class="progress-bar-wrapper" id="migrate-progress-wrapper" style="display: none;">\n                        <div class="progress-bar-fill" id="migrate-progress-fill"></div>\n                    </div>\n                </div>\n            </div>\n\n            <!-- TAB 3: CURATOR & EDITOR VIEW -->\n            <div class="content-section" id="edit-tab">\n                <div id="no-listing-selected" style="text-align: center; padding: 50px 0; color: var(--text-muted);">\n                    <h3>👈 Vui lòng chọn 1 căn nhà từ danh sách bên trái để bắt đầu Biên tập & Xuất bản!</h3>\n                </div>\n\n                <div id="editor-active" style="display: none;">\n                    <div id="editor-error-banner" style="display: none; background: rgba(239, 68, 68, 0.08); border: 1px solid var(--accent-red); border-radius: 8px; padding: 12px; margin-bottom: 15px;">\n                        <div style="font-weight: bold; color: var(--accent-red); font-size: 13px; margin-bottom: 5px; display: flex; align-items: center; gap: 6px;">\n                            ⚠️ PHÁT HIỆN SỰ CỐ CÀO TIN (CRAWL ERROR)\n                        </div>\n                        <div style="font-size: 12px; color: var(--text-main); margin-bottom: 10px;">\n                            Lý do lỗi: <strong id="editor-error-reason" style="color: var(--accent-red);">[Reason]</strong>\n                        </div>\n                        <div style="display: flex; gap: 8px;">\n                            <button class="btn" onclick="recrawlActiveListing()" style="font-size: 11px; padding: 4px 10px; background: rgba(251, 191, 36, 0.15); border: 1px solid var(--accent-gold); color: var(--accent-gold); height: auto;">🔄 Thử cào lại</button>\n                            <button class="btn" onclick="deleteActiveListing()" style="font-size: 11px; padding: 4px 10px; background: rgba(239, 68, 68, 0.15); border: 1px solid var(--accent-red); color: var(--accent-red); height: auto;">🗑️ Xóa khỏi SQLite</button>\n                        </div>\n                    </div>\n                    <div class="editor-container">\n                        <!-- Left Panel: Images and classification -->\n                        <div>\n                            <div class="panel-card image-station">\n                                <div class="panel-title">🖼️ Trạm Phân Loại & Dán Nhãn Hình Ảnh</div>\n                                <p style="font-size: 12px; color: var(--text-muted); margin-bottom: 10px;">\n                                    Gán vai trò cho ảnh bằng mắt. Ảnh bìa (Cover) và Mặt tiền cực kỳ quan trọng. Thứ tự ảnh sẽ được lưu lại chuẩn xác khi chuyển cột.\n                                </p>\n                                <div class="image-grid" id="curator-image-grid">\n                                    <!-- Dynamic images cards here -->\n                                </div>\n                            </div>\n                        </div>\n\n                        <!-- Right Panel: Data values editor -->\n                        <div class="panel-card editor-form" style="max-height: calc(100vh - 120px); overflow-y: auto;">\n                            \n\n\n                            <!-- PHẦN 1: BIÊN TẬP THÔNG TIN (KHANG NGÔ) -->\n                            <div class="panel-title" style="border-bottom: 1px solid var(--border-color); padding-bottom: 8px; margin-bottom: 15px;">\n                                ✍️ BIÊN TẬP ĐỊA CHỈ THỰC TẾ\n                            </div>\n\n                            <div class="editor-grid-2">\n                                <div class="form-group">\n                                    <label>Số nhà</label>\n                                    <input type="text" id="edit-ngo-so-nha" placeholder="VD: 123/45" oninput="updateMaKhangNgoLive()">\n                                </div>\n                                <div class="form-group">\n                                    <label>Đường</label>\n                                    <input type="text" id="edit-duong" placeholder="VD: Sư Vạn Hạnh" oninput="updateMaKhangNgoLive()">\n                                </div>\n                            </div>\n\n                            <div class="editor-grid-2">\n                                <div class="form-group">\n                                    <label>Phường</label>\n                                    <input type="text" id="edit-phuong" placeholder="VD: Phường 12">\n                                </div>\n                                <div class="form-group">\n                                    <label>Quận</label>\n                                    <input type="text" id="edit-quan" placeholder="VD: Quận 10" oninput="updateMaKhangNgoLive()">\n                                </div>\n                            </div>\n\n                            <div style="margin-top: 15px; padding-top: 15px; border-top: 1px dashed rgba(255,255,255,0.08); display: flex; flex-direction: column; gap: 12px;">\n                                <div class="form-group" style="margin-bottom: 0; width: 100%;">\n                                    <label style="color: var(--accent-gold); font-weight: bold;">🔑 MÃ KHANG NGÔ (ID)</label>\n                                    <input type="text" id="edit-ma-khang-ngo" style="width: 100%; background: rgba(251, 191, 36, 0.08); border: 1px solid var(--accent-gold); color: var(--accent-gold); font-weight: bold; font-family: monospace; font-size: 16px; letter-spacing: 1px; padding: 10px 12px; box-sizing: border-box;" placeholder="Tự động sinh...">\n                                </div>\n                                <button class="btn btn-gold" id="btn-run-ai" style="width: 100%; height: 42px; display: flex; align-items: center; justify-content: center; gap: 8px; font-weight: bold; margin-top: 4px;" onclick="runAiCuration()">\n                                    <span id="ai-btn-text">🤖 BIÊN TẬP AI</span>\n                                    <div class="spinner-small" id="ai-spinner" style="display: none;"></div>\n                                </button>\n                            </div>\n\n                            <!-- PHẦN 1.5: BIÊN TẬP BÀI ĐĂNG PUBLIC (DÀNH CHO AI & PUBLIC FIELDS) -->\n                            <div class="panel-title" style="border-bottom: 1px solid var(--border-color); padding-bottom: 8px; margin-top: 25px; margin-bottom: 15px; color: var(--accent-gold);">\n                                🤖 THÔNG TIN BIÊN TẬP PUBLIC (LÊN SHEET SOURCE)\n                            </div>\n                            \n                            <div style="font-size: 11px; color: var(--accent-gold); margin-top: -5px; margin-bottom: 15px; opacity: 0.9; display: flex; align-items: flex-start; gap: 6px; background: rgba(251, 191, 36, 0.05); padding: 8px 12px; border-left: 3px solid var(--accent-gold); border-radius: 4px;">\n                                <span style="font-size: 14px; line-height: 1;">💡</span>\n                                <span style="line-height: 1.4;"><i>Mẹo: Hệ thống tự động chạy AI Biên tập thầm lặng (Silent Auto-AI) khi Trang chọn căn thô mới mà Tiêu đề/Mô tả Public đang trống. Bấm nút 🤖 BIÊN TẬP AI ở trên nếu muốn sinh lại.</i></span>\n                            </div>\n                            \n                            <div class="form-group">\n                                <label>Tiêu đề Public (SEO v5)</label>\n                                <input type="text" id="edit-tieu-de-public" placeholder="Tiêu đề chuẩn SEO xuất bản..." style="font-weight: 500;">\n                            </div>\n                            \n                            <div class="form-group" style="margin-top: 10px;">\n                                <label>Mô tả Public (Sạch sẽ, Không Emoji)</label>\n                                <textarea id="edit-mo-ta-public" rows="6" placeholder="Mô tả bài viết sạch sẽ..." style="resize: vertical; font-family: monospace; font-size: 12px; color: var(--text-main); background: rgba(0,0,0,0.2); border: 1px solid var(--border-color); border-radius: 6px; padding: 8px; width: 100%; box-sizing: border-box;"></textarea>\n                            </div>\n                            \n                            <div class="editor-grid-2" style="margin-top: 10px;">\n                                <div class="form-group">\n                                    <label>Giá Public (Tỷ)</label>\n                                    <input type="text" id="edit-gia-public" placeholder="Giá chào công khai...">\n                                </div>\n                                <div class="form-group">\n                                    <label>Phân loại Hẻm</label>\n                                    <select id="edit-phan-loai-hem">\n                                        <option value="Mặt tiền">Mặt tiền</option>\n                                        <option value="Hẻm xe hơi">Hẻm xe hơi</option>\n                                        <option value="Hẻm ba gác">Hẻm ba gác</option>\n                                        <option value="Hẻm thông">Hẻm thông</option>\n                                    </select>\n                                </div>\n                            </div>\n                            \n                            <div class="editor-grid-2" style="margin-top: 10px;">\n                                <div class="form-group">\n                                    <label>Độ rộng hẻm/đường (m)</label>\n                                    <input type="text" id="edit-duong-truoc-nha" placeholder="Độ rộng...">\n                                </div>\n                                <div class="form-group">\n                                    <label>Tình trạng nhà</label>\n                                    <select id="edit-tinh-trang-nha">\n                                        <option value="Bình thường">Bình thường</option>\n                                        <option value="Mới">Mới</option>\n                                        <option value="Nát">Nát</option>\n                                        <option value="Đã bán">Đã bán (Ẩn)</option>\n                                        <option value="Ẩn">Ẩn</option>\n                                    </select>\n                                </div>\n                            </div>\n                            \n                            <div class="editor-grid-2" style="margin-top: 10px;">\n                                <div class="form-group">\n                                    <label>Mặt tiền (m)</label>\n                                    <input type="text" id="edit-mat-tien" placeholder="Mặt tiền...">\n                                </div>\n                                <div class="form-group">\n                                    <label>Chiều dài (m)</label>\n                                    <input type="text" id="edit-chieu-dai" placeholder="Chiều dài...">\n                                </div>\n                            </div>\n                            \n                            <div class="editor-grid-2" style="margin-top: 10px;">\n                                <div class="form-group">\n                                    <label>Số phòng ngủ</label>\n                                    <input type="text" id="edit-so-phong-ngu" placeholder="Số PN...">\n                                </div>\n                                <div class="form-group">\n                                    <label>Số toilet</label>\n                                    <input type="text" id="edit-so-nha-ve-sinh" placeholder="Số WC...">\n                                </div>\n                            </div>\n                            \n                            <div class="form-group" style="margin-top: 10px;">\n                                <label>Phường cũ (AI - Lịch sử sáp nhập)</label>\n                                <input type="text" id="edit-phuong-cu-ai" placeholder="Phường cũ trước sáp nhập...">\n                            </div>\n                            \n                            <div class="editor-grid-3" style="margin-top: 10px;">\n                                <div class="form-group">\n                                    <label>Đánh giá</label>\n                                    <select id="edit-danh-gia">\n                                        <option value="">(Trống - Bình thường)</option>\n                                        <option value="Hàng Ngon">💎 Hàng Ngon</option>\n                                        <option value="Hàng Lỗi">⚠️ Hàng Lỗi</option>\n                                    </select>\n                                </div>\n                                <div class="form-group">\n                                    <label>Ngủ trệt</label>\n                                    <select id="edit-ngu-tret">\n                                        <option value="">Không</option>\n                                        <option value="Có">Có</option>\n                                    </select>\n                                </div>\n                                <div class="form-group">\n                                    <label>CHDV</label>\n                                    <select id="edit-chdv">\n                                        <option value="">Không</option>\n                                        <option value="Có">Có</option>\n                                    </select>\n                                </div>\n                            </div>\n\n                            <!-- PHẦN 2: THÔNG TIN GỐC CÀO ĐƯỢC (THIÊN KHÔI) -->\n                            <div class="panel-title" style="border-bottom: 1px solid var(--border-color); padding-bottom: 8px; margin-top: 20px; margin-bottom: 15px; color: var(--accent-cyan);">\n                                📡 THÔNG TIN GỐC CÀO ĐƯỢC (THIÊN KHÔI)\n                            </div>\n\n                            <div style="background: rgba(15, 23, 42, 0.4); padding: 15px; border-radius: 12px; border: 1px solid var(--border-color); font-size: 13px; line-height: 1.6; display: flex; flex-direction: column; gap: 12px;">\n                                \n                                <!-- Nhóm 1: Địa lý & Tổng quan -->\n                                <div style="font-weight: bold; color: var(--accent-gold); font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 3px;">\n                                    📍 Địa Lý & Tổng Quan\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Mã hàng: <strong id="raw-ma-hang" style="color: var(--text-main);"></strong></div>\n                                    <div>Giá chào: <strong id="raw-gia-chao" style="color: var(--accent-gold);"></strong> tỷ</div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Tỉnh thành: <strong id="raw-tinh-thanh" style="color: var(--text-main);"></strong></div>\n                                    <div>Quận huyện: <strong id="raw-quan-huyen" style="color: var(--text-main);"></strong></div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Phường xã: <strong id="raw-phuong-xa" style="color: var(--text-main);"></strong></div>\n                                    <div>Hướng nhà: <strong id="raw-huong" style="color: var(--text-main);"></strong></div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Số nhà: <strong id="raw-so-nha" style="color: var(--text-main);"></strong></div>\n                                    <div>Đường: <strong id="raw-duong-pho" style="color: var(--text-main);"></strong></div>\n                                </div>\n                                \n                                <!-- Nhóm 2: Diện tích & Kết cấu -->\n                                <div style="font-weight: bold; color: var(--accent-gold); font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 3px; margin-top: 5px;">\n                                    📐 Diện Tích & Kết Cấu\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>DT Thực tế: <strong id="raw-dt-thuc-te" style="color: var(--text-main);"></strong> m²</div>\n                                    <div>DT Trên sổ: <strong id="raw-dt-tren-so" style="color: var(--text-main);"></strong> m²</div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Mặt tiền: <strong id="raw-mat-tien" style="color: var(--text-main);"></strong> m</div>\n                                    <div>Chiều dài: <strong id="raw-chieu-dai" style="color: var(--text-main);"></strong></div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Đường trước nhà: <strong id="raw-duong-truoc-nha" style="color: var(--text-main);"></strong> m</div>\n                                    <div>Số tầng: <strong id="raw-so-tang" style="color: var(--text-main);"></strong> tầng</div>\n                                </div>\n                                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 10px;">\n                                    <div>Số phòng ngủ: <strong id="raw-so-phong-ngu" style="color: var(--text-main);"></strong></div>\n                                    <div>Số vệ sinh: <strong id="raw-so-nha-ve-sinh" style="color: var(--text-main);"></strong></div>\n                                </div>\n\n                                <!-- Nhóm 3: Đầu chủ & Hợp đồng -->\n                                <div style="font-weight: bold; color: var(--accent-gold); font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 3px; margin-top: 5px;">\n                                    🤝 Đầu Chủ & Hợp Đồng\n                                </div>\n                                <div>Tên đầu chủ: <strong id="raw-ten-dau-chu" style="color: var(--text-main);"></strong></div>\n                                <div>ĐT đầu chủ: <strong id="raw-dt-dau-chu" style="color: var(--text-main);"></strong></div>\n                                <div>\n                                    Điểm Facebook: <a id="raw-link-fb" href="#" target="_blank" style="color: var(--accent-cyan); font-weight: bold; text-decoration: underline; display: none;">Mở Facebook đầu chủ ➔</a>\n                                    <span id="raw-no-fb" style="color: var(--text-muted); display: inline;">Không có link Facebook</span>\n                                </div>\n\n\n\n                                <!-- Nhóm 5: Nội dung & Mô tả -->\n                                <div style="font-weight: bold; color: var(--accent-gold); font-size: 11px; text-transform: uppercase; letter-spacing: 0.5px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 3px; margin-top: 5px;">\n                                    📝 Nội Dung & Mô Tả\n                                </div>\n                                <div>\n                                    <div style="font-weight: 500; color: var(--text-muted); margin-bottom: 4px;">Nội dung chính:</div>\n                                    <div id="raw-noi-dung-chinh" style="max-height: 120px; overflow-y: auto; background: rgba(0,0,0,0.3); padding: 8px; border-radius: 6px; font-family: monospace; white-space: pre-wrap; color: var(--text-muted);"></div>\n                                </div>\n\n                                <div>\n                                    <div style="font-weight: 500; color: var(--text-muted); margin-bottom: 4px;">Mô tả chi tiết:</div>\n                                    <div id="raw-mo-ta-chi-tiet" style="max-height: 150px; overflow-y: auto; background: rgba(0,0,0,0.3); padding: 8px; border-radius: 6px; font-family: monospace; white-space: pre-wrap; color: var(--text-muted);"></div>\n                                </div>\n                            </div>\n\n                            <div style="display: flex; flex-direction: column; gap: 10px; margin-top: 20px;">\n                                <button class="btn btn-outline" style="width: 100%;" onclick="saveListingEdits()">💾 LƯU THAY ĐỔI CỤC BỘ</button>\n                                <button class="btn btn-green" style="width: 100%;" onclick="publishToSheets()">🚀 XUẤT BẢN THẲNG LÊN GOOGLE SHEET</button>\n                                <button class="btn" style="width: 100%; background: rgba(251, 191, 36, 0.15); border: 1px solid var(--accent-gold); color: var(--accent-gold); margin-top: 5px;" onclick="recrawlActiveListing()">🔄 CÀO LẠI CĂN NÀY (ĐÈ DỮ LIỆU)</button>\n                                <button class="btn" style="width: 100%; background: rgba(239, 68, 68, 0.15); border: 1px solid var(--accent-red); color: var(--accent-red); margin-top: 5px;" onclick="deleteActiveListing()">🗑️ XÓA CĂN NÀY KHỎI SQLite</button>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n            <!-- TAB 4: CRAWL SESSION HISTORY -->\n            <div class="content-section" id="history-tab">\n                <div class="panel-row" style="margin-bottom: 20px;">\n                    <div class="panel-card" style="width: 100%;">\n                        <div class="panel-title">📊 Tổng quan Lịch sử cào (Analytics)</div>\n                        <div class="metrics-grid" style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 15px; margin-top: 15px;">\n                            <div class="metric-card" style="background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 15px; text-align: center;">\n                                <div style="font-size: 11px; color: var(--text-muted); text-transform: uppercase; margin-bottom: 5px;">Tổng số phiên cào</div>\n                                <div id="total-sessions-val" style="font-size: 24px; font-weight: bold; color: var(--accent-cyan);">0</div>\n                            </div>\n                            <div class="metric-card" style="background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 15px; text-align: center;">\n                                <div style="font-size: 11px; color: var(--text-muted); text-transform: uppercase; margin-bottom: 5px;">Căn cào thành công</div>\n                                <div id="total-crawled-val" style="font-size: 24px; font-weight: bold; color: var(--text-green);">0</div>\n                            </div>\n                            <div class="metric-card" style="background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 15px; text-align: center;">\n                                <div style="font-size: 11px; color: var(--text-muted); text-transform: uppercase; margin-bottom: 5px;">Tổng thời gian cào</div>\n                                <div id="total-duration-val" style="font-size: 24px; font-weight: bold; color: var(--accent-gold);">0s</div>\n                            </div>\n                            <div class="metric-card" style="background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 15px; text-align: center;">\n                                <div style="font-size: 11px; color: var(--text-muted); text-transform: uppercase; margin-bottom: 5px;">Tốc độ trung bình</div>\n                                <div id="overall-speed-val" style="font-size: 24px; font-weight: bold; color: var(--text-main);">N/A</div>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n\n                <div class="panel-row">\n                    <div class="panel-card" style="width: 100%;">\n                        <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;">\n                            <div class="panel-title" style="margin-bottom: 0;">📜 Danh sách các phiên cào</div>\n                            <button class="btn btn-outline" style="padding: 5px 12px; font-size: 11px;" onclick="loadCrawlSessions()">🔄 Tải lại</button>\n                        </div>\n                        <div class="table-container" style="overflow-x: auto; background: rgba(0,0,0,0.2); border-radius: 8px; border: 1px solid rgba(255,255,255,0.05);">\n                            <table style="width: 100%; border-collapse: collapse; text-align: left; font-size: 12px;">\n                                <thead>\n                                    <tr style="border-bottom: 1px solid rgba(255,255,255,0.1); background: rgba(255,255,255,0.02); color: var(--text-muted);">\n                                        <th style="padding: 12px 15px;">Bắt đầu</th>\n                                        <th style="padding: 12px 15px;">Cookie ID</th>\n                                        <th style="padding: 12px 15px;">Thời lượng</th>\n                                        <th style="padding: 12px 15px;">Số căn</th>\n                                        <th style="padding: 12px 15px;">Tốc độ</th>\n                                        <th style="padding: 12px 15px;">Trạng thái</th>\n                                    </tr>\n                                </thead>\n                                <tbody id="sessions-table-body">\n                                    <!-- Rendered dynamically -->\n                                    <tr>\n                                        <td colspan="6" style="padding: 20px; text-align: center; color: var(--text-muted);">Đang tải lịch sử...</td>\n                                    </tr>\n                                </tbody>\n                            </table>\n                        </div>\n                    </div>\n                </div>\n            </div>\n\n        </div>\n\n    </div>\n\n    <!-- Modal: Paste & Cache Cookie -->\n    <div class="modal-overlay" id="cookie-modal">\n        <div class="modal-box" style="max-width: 500px;">\n            <div class="modal-title">\n                <span>🔑 Cập Nhật Cookie Thiên Khôi</span>\n                <span class="modal-close" onclick="closeCookieModal()">&times;</span>\n            </div>\n            <div class="cookie-modal-inner">\n                <p style="font-size: 13px; color: var(--text-muted); line-height: 1.6;">\n                    Do cơ chế bảo mật nghiêm ngặt của Chrome 120+ (App-Bound encryption v20), Python không thể trực tiếp bóc tách cookie đăng nhập của bạn từ ổ cứng Windows khi Chrome đang mở.\n                </p>\n                <div class="alert-box" style="background: rgba(59, 130, 246, 0.08); border-color: rgba(59, 130, 246, 0.2); color: #60a5fa;">\n                    <strong>Hướng dẫn lấy Cookie 1-Click:</strong>\n                    <ol style="margin-left: 15px; margin-top: 5px;">\n                        <li>Cài đặt extension Chrome "Copy All Cookies".</li>\n                        <li>Mở tab Thiên Khôi (data.thienkhoi.com) đã đăng nhập.</li>\n                        <li>Click biểu tượng extension sao chép.</li>\n                        <li>Dán (Ctrl + V) chuỗi đó vào khung bên dưới.</li>\n                    </ol>\n                </div>\n                <div class="form-group">\n                    <label>Chuỗi Cookie đăng nhập</label>\n                    <textarea id="user-cookie-input" rows="5" placeholder="deviceid=af696161...; .AspNet.ApplicationCookie=yfFsOs..."></textarea>\n                </div>\n                <button class="btn btn-gold" onclick="saveCookieCache()">💾 Lưu Cookie & Đồng Bộ Cục Bộ</button>\n            </div>\n        </div>\n    </div>\n\n    <!-- Modal: Sheet Row Copier (Fallback khi không có credentials) -->\n    <div class="modal-overlay" id="copier-modal">\n        <div class="modal-box">\n            <div class="modal-title">\n                <span>📋 Dòng Dữ Liệu 79 Cột Pool Sẵn Sàng</span>\n                <span class="modal-close" onclick="closeCopierModal()">&times;</span>\n            </div>\n            <p style="font-size: 13px; color: var(--text-muted); line-height: 1.5; margin-bottom: 15px;">\n                Do chưa cấu hình file xác thực tài khoản dịch vụ <strong style="color: var(--accent-gold);">credentials.json</strong> lên local server, hệ thống không thể tự ghi dữ liệu lên Google Sheets. Tuy nhiên, toàn bộ dữ liệu 79 cột đồng bộ chuẩn đã được biên dịch hoàn chỉnh dưới đây:\n            </p>\n            <textarea class="raw-data-textarea" id="copy-table-data" readonly></textarea>\n            <div style="display: flex; gap: 10px;">\n                <button class="btn btn-gold" onclick="copyRowToClipboard()">📋 SAO CHÉP DÒNG DỮ LIỆU</button>\n                <button class="btn btn-outline" onclick="closeCopierModal()">Đóng cửa sổ</button>\n            </div>\n        </div>\n    </div>\n\n    <script>\n        // Trạng thái cục bộ của UI\n        let sidebarStatus = \'raw_text\';\n        let activeListingId = null;\n        let activeListingData = null;\n        let imagesConfig = []; // Mảng chứa ảnh và vai trò\n        let logsInterval = null;\n        let cookieExpiredAlerted = false;\n        let lastLogsSignature = "";\n\n        // ==========================================\n        // KHANG NGÔ REAL-TIME ID & AI CURATION CORE\n        // ==========================================\n        function updateMaKhangNgoLive() {\n            const soNha = document.getElementById(\'edit-ngo-so-nha\').value;\n            const duong = document.getElementById(\'edit-duong\').value;\n            const quan = document.getElementById(\'edit-quan\').value;\n            \n            const newId = genIdKhangNgo(soNha, duong, quan);\n            document.getElementById(\'edit-ma-khang-ngo\').value = newId;\n            if (activeListingData) {\n                activeListingData.Ma_Khang_Ngo_ID = newId;\n            }\n        }\n\n        function genIdKhangNgo(soNha, duong, quan) {\n            soNha = (soNha || "").toString().trim();\n            if (soNha.includes(\'+\')) {\n                soNha = soNha.split(\'+\')[0].trim();\n            }\n            \n            duong = (duong || "").toString().trim();\n            quan = (quan || "").toString().trim();\n            \n            // 1. Mã hóa số nhà (Số -> Chữ in hoa, Ký tự -> thường)\n            const digitMap = {\n                \'1\': \'M\', \'2\': \'H\', \'3\': \'B\', \'4\': \'A\', \'5\': \'N\',\n                \'6\': \'S\', \'7\': \'Z\', \'8\': \'T\', \'9\': \'C\', \'0\': \'O\',\n                \'/\': \'I\', \'.\': \'I\'\n            };\n            let maSoNha = "";\n            for (let i = 0; i < soNha.length; i++) {\n                const char = soNha[i];\n                if (digitMap[char]) {\n                    maSoNha += digitMap[char];\n                } else if (char.match(/[a-zA-Z]/)) {\n                    maSoNha += char.toLowerCase();\n                }\n            }\n            \n            // 2. Normalization: Các tên đường có biến thể đặc biệt\n            let normalizedDuong = duong;\n            if (normalizedDuong.match(/cách mạng tháng (tám|8)|cmt8/i)) {\n                normalizedDuong = "CMTT";\n            } else if (normalizedDuong.match(/ba tháng hai|3 tháng 2|3\\/2|3\\-2/i)) {\n                normalizedDuong = "BTH";\n            } else if (normalizedDuong.match(/đường số (\\d+)/i)) {\n                const match = normalizedDuong.match(/đường số (\\d+)/i);\n                normalizedDuong = "DS" + match[1];\n            }\n            \n            // Viết tắt tên đường (Lấy chữ cái đầu của mỗi từ)\n            let abbrDuong = "";\n            if (normalizedDuong === "CMTT" || normalizedDuong === "BTH") {\n                abbrDuong = normalizedDuong;\n            } else if (normalizedDuong.startsWith("DS")) {\n                abbrDuong = normalizedDuong;\n            } else {\n                const noTones = removeVietnameseTones(normalizedDuong);\n                const words = noTones.split(/\\s+/);\n                for (let k = 0; k < words.length; k++) {\n                    const word = words[k];\n                    if (word.length > 0) {\n                        const firstChar = word[0].toUpperCase();\n                        abbrDuong += firstChar;\n                    }\n                }\n            }\n            \n            // 3. Đảo ngược chuỗi viết tắt (Reversed)\n            const reversedDuong = abbrDuong.split(\'\').reverse().join(\'\');\n            \n            // 4. Ghép nối: [Mã Số Nhà] + \'I\' + [Tên Đường Viết Tắt Đảo Ngược]\n            let combined = maSoNha + "I" + reversedDuong;\n            \n            // 5. Ciphering: Chèn \'W\' vào vị trí thứ 2\n            if (combined.length > 1) {\n                combined = combined.substring(0, 1) + "W" + combined.substring(1);\n            } else {\n                combined = combined + "W";\n            }\n            \n            return combined;\n        }\n        \n        function removeVietnameseTones(str) {\n            str = str.replace(/à|á|ạ|ả|ã|â|ầ|ấ|ậ|ẩ|ẫ|ă|ằ|ắ|ặ|ẳ|ẵ/g, "a");\n            str = str.replace(/è|é|ẹ|ẻ|ẽ|ê|ề|ế|ệ|ể|ễ/g, "e");\n            str = str.replace(/ì|í|ị|ỉ|ĩ/g, "i");\n            str = str.replace(/ò|ó|ọ|ỏ|õ|ô|ồ|ố|ộ|ổ|ỗ|ơ|ờ|ớ|ợ|ở|ỡ/g, "o");\n            str = str.replace(/ù|ú|ụ|ủ|ũ|ư|ừ|ứ|ự|ử|ữ/g, "u");\n            str = str.replace(/ỳ|ý|ỵ|ỷ|ỹ/g, "y");\n            str = str.replace(/đ/g, "d");\n            str = str.replace(/À|Á|Ạ|Ả|Ã|Â|Ầ|Ấ|Ậ|Ẩ|Ẫ|Ă|Ằ|Ắ|Ặ|Ẳ|Ẵ/g, "A");\n            str = str.replace(/È|É|Ẹ|Ẻ|Ẽ|Ê|Ề|Ế|Ệ|Ể|Ễ/g, "E");\n            str = str.replace(/Ì|Í|Ị|Ỉ|Ĩ/g, "I");\n            str = str.replace(/Ò|Ó|Ọ|Ỏ|Õ|Ô|Ồ|Ố|Ộ|Ổ|Ỗ|Ơ|Ờ|Ớ|Ợ|Ở|Ỡ/g, "O");\n            str = str.replace(/Ù|Ú|Ụ|Ủ|Ũ|Ư|Ừ|Ứ|Ự|Ử|Ữ/g, "U");\n            str = str.replace(/Ỳ|Ý|Ỵ|Ỷ|Ỹ/g, "Y");\n            str = str.replace(/Đ/g, "D");\n            return str;\n        }\n\n        function runAiCuration() {\n            if (!activeListingData) {\n                alert("Vui lòng chọn 1 căn nhà từ danh sách bên trái để chạy AI biên tập!");\n                return;\n            }\n            \n            const confirmProceed = confirm("Hành động này sẽ xóa thông tin Tiêu đề public và Mô tả public cũ để thay bằng thông tin mới tự động điền bằng AI. Bạn có chắc chắn muốn tiếp tục không?");\n            if (!confirmProceed) return;\n            \n            const btn = document.getElementById(\'btn-run-ai\');\n            const spinner = document.getElementById(\'ai-spinner\');\n            const btnText = document.getElementById(\'ai-btn-text\');\n            \n            btn.disabled = true;\n            spinner.style.display = \'inline-block\';\n            btnText.innerText = \'ĐANG CHẠY AI...\';\n            \n            const payload = {\n                soNha: document.getElementById(\'edit-ngo-so-nha\').value,\n                duong: document.getElementById(\'edit-duong\').value,\n                phuong: document.getElementById(\'edit-phuong\').value,\n                quan: document.getElementById(\'edit-quan\').value,\n                noiDungChinh: activeListingData.Noi_dung_chinh || \'\',\n                moTaChiTiet: activeListingData.Mo_ta_chi_tiet || \'\',\n                dtThucTe: activeListingData.DT_Thuc_te || \'\',\n                dtTrenSo: activeListingData.DT_Tren_so || \'\',\n                matTien: activeListingData.Mat_Tien || \'\',\n                soTang: activeListingData.So_Tang || \'\',\n                soPhongNgu: document.getElementById(\'edit-so-phong-ngu\').value || activeListingData.So_phong_ngu || \'\',\n                soToilet: document.getElementById(\'edit-so-nha-ve-sinh\').value || activeListingData.So_nha_ve_sinh || \'\',\n                giaChao: activeListingData.Gia_chao || \'\',\n                duongTruocNha: document.getElementById(\'edit-duong-truoc-nha\').value || activeListingData.Duong_truoc_nha_m || \'\',\n                phanLoaiHem: document.getElementById(\'edit-phan-loai-hem\').value || activeListingData.Phan_loai_Hem || \'\',\n                phanLoai: activeListingData.Phan_loai || \'\'\n            };\n            \n            fetch(\'/api/ai/generate\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify(payload)\n            })\n            .then(res => {\n                if (!res.ok) {\n                    return res.json().then(errData => {\n                        throw new Error(errData.message || "Lỗi khi gọi API OpenAI.");\n                    });\n                }\n                return res.json();\n            })\n            .then(data => {\n                if (data.status === \'success\') {\n                    // Điền kết quả vào visual form fields\n                    document.getElementById(\'edit-tieu-de-public\').value = data.tieu_de_public || \'\';\n                    document.getElementById(\'edit-mo-ta-public\').value = data.mo_ta_public || \'\';\n                    document.getElementById(\'edit-phuong-cu-ai\').value = data.phuong_cu || \'\';\n                    \n                    // Cập nhật local activeListingData\n                    activeListingData.Tieu_de_Public = data.tieu_de_public || \'\';\n                    activeListingData.Mo_ta_Public = data.mo_ta_public || \'\';\n                    activeListingData.Phuong_cu_AI_ = data.phuong_cu || \'\';\n                    \n                    showBannerNotification(\'🤖 AI đã biên tập Tiêu đề, Mô tả và tra Phường cũ thành công!\', \'green\');\n                } else {\n                    alert(\'Lỗi biên tập AI: \' + data.message);\n                }\n            })\n            .catch(err => {\n                showBannerNotification(\'⚠️ \' + err.message, \'error\');\n                playWarningSound();\n            })\n            .finally(() => {\n                btn.disabled = false;\n                spinner.style.display = \'none\';\n                btnText.innerText = \'🤖 BIÊN TẬP AI\';\n            });\n        }\n        \n        function playWarningSound() {\n            try {\n                const audioCtx = new (window.AudioContext || window.webkitAudioContext)();\n                \n                // Phát âm thanh bíp cảnh báo kép (Double-Beep) chất lượng cao\n                const playBeep = (freq, duration, delay) => {\n                    setTimeout(() => {\n                        const osc = audioCtx.createOscillator();\n                        const gain = audioCtx.createGain();\n                        osc.type = \'sine\';\n                        osc.frequency.setValueAtTime(freq, audioCtx.currentTime);\n                        \n                        gain.gain.setValueAtTime(0.3, audioCtx.currentTime);\n                        gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + duration);\n                        \n                        osc.connect(gain);\n                        gain.connect(audioCtx.destination);\n                        osc.start();\n                        osc.stop(audioCtx.currentTime + duration);\n                    }, delay);\n                };\n                \n                playBeep(880, 0.15, 0);       // Nốt cao 1\n                playBeep(880, 0.15, 200);     // Nốt cao 2\n                playBeep(440, 0.4, 400);      // Nốt trầm cảnh báo\n            } catch (e) {\n                console.error("Lỗi phát âm thanh cảnh báo:", e);\n            }\n        }\n        \n        function triggerCookieExpiredAlert() {\n            if (cookieExpiredAlerted) return;\n            cookieExpiredAlerted = true;\n            \n            // Phát âm thanh cảnh báo\n            playWarningSound();\n            \n            // Hiển thị Toast nổi cảnh báo trực quan\n            showToast("🚨 CẢNH BÁO: Phiên đăng nhập (Cookie) Thiên Khôi đã hết hạn! Vui lòng cập nhật Cookie mới.", "error");\n\n            // Tự động mở Modal Cập nhật Cookie để anh Khang tiện dán ngay lập tức\n            openCookieModal();\n            const textarea = document.getElementById(\'user-cookie-input\');\n            if (textarea) {\n                textarea.value = ""; // Xóa dữ liệu cũ để sẵn sàng dán\n                textarea.focus();\n            }\n        }\n\n        // Bật polling lấy logs console\n        window.addEventListener(\'DOMContentLoaded\', () => {\n            fetchConfig();\n            fetchListings();\n            loadTroubleList();\n            logsInterval = setInterval(fetchLogs, 2000);\n            \n            // Tự động phân tích trang bắt đầu từ URL khi dán/nhập\n            document.getElementById(\'crawl-url\').addEventListener(\'input\', (e) => {\n                const val = e.target.value.trim();\n                if (!val) return;\n                try {\n                    const urlObj = new URL(val);\n                    const page = urlObj.searchParams.get(\'Page\') || urlObj.searchParams.get(\'page\') || urlObj.searchParams.get(\'p\');\n                    if (page) {\n                        const pageNum = parseInt(page);\n                        if (!isNaN(pageNum) && pageNum > 0) {\n                            document.getElementById(\'crawl-start-page\').value = pageNum;\n                            showBannerNotification(`💡 Tự động phát hiện Trang bắt đầu: ${pageNum}`, \'gold\');\n                        }\n                    }\n                } catch (err) {}\n            });\n        });\n\n        // ==========================================\n        // CẤU HÌNH & TRẠNG THÁI\n        // ==========================================\n        function onSpeedPresetChange(preset) {\n            const houseMinInput = document.getElementById(\'cfg-delay-house-min\');\n            const houseMaxInput = document.getElementById(\'cfg-delay-house-max\');\n            const pageMinInput = document.getElementById(\'cfg-delay-page-min\');\n            const pageMaxInput = document.getElementById(\'cfg-delay-page-max\');\n            const alertDiv = document.getElementById(\'speed-preset-alert-text\');\n\n            if (preset === \'safe\') {\n                houseMinInput.value = 8.0;\n                houseMaxInput.value = 15.0;\n                pageMinInput.value = 20.0;\n                pageMaxInput.value = 40.0;\n                alertDiv.innerHTML = `<strong>🟢 Chế độ An toàn (Stealth Mode) đang bật:</strong> Nghỉ ngẫu nhiên 8 - 15 giây giữa các căn và 20 - 40 giây khi chuyển trang. An toàn tuyệt đối, giả lập 100% người dùng thực tế.`;\n            } else if (preset === \'optimal\') {\n                houseMinInput.value = 3.0;\n                houseMaxInput.value = 6.0;\n                pageMinInput.value = 5.0;\n                pageMaxInput.value = 10.0;\n                alertDiv.innerHTML = `<strong>🟡 Chế độ Tối ưu (Fast & Safe) đang bật:</strong> Nghỉ ngẫu nhiên 3 - 6 giây giữa các căn và 5 - 10 giây khi chuyển trang. Tăng tốc độ cào ~2.5 lần nhưng vẫn bảo đảm an toàn chống chặn Cookie.`;\n            } else if (preset === \'turbo\') {\n                houseMinInput.value = 1.5;\n                houseMaxInput.value = 3.0;\n                pageMinInput.value = 3.0;\n                pageMaxInput.value = 5.0;\n                alertDiv.innerHTML = `<strong>🔴 Chế độ Siêu tốc (Turbo Mode) đang bật:</strong> Nghỉ ngẫu nhiên 1.5 - 3 giây giữa các căn và 3 - 5 giây khi chuyển trang. Tốc độ cào cực nhanh (~6 lần) nhưng hãy lưu ý IP hoặc Cookie có thể nhanh hết hạn hơn.`;\n            } else if (preset === \'custom\') {\n                alertDiv.innerHTML = `<strong>⚙️ Chế độ Tùy chỉnh đang bật:</strong> Thời gian chờ sẽ dựa trên các thông số cấu hình cụ thể do bạn thiết lập ở bảng bên phải.`;\n            }\n            \n            // Tự động lưu cấu hình mới\n            saveConfig();\n        }\n\n        function detectAndSetPresetDropdown() {\n            const houseMin = parseFloat(document.getElementById(\'cfg-delay-house-min\').value);\n            const houseMax = parseFloat(document.getElementById(\'cfg-delay-house-max\').value);\n            const pageMin = parseFloat(document.getElementById(\'cfg-delay-page-min\').value);\n            const pageMax = parseFloat(document.getElementById(\'cfg-delay-page-max\').value);\n            const presetSelect = document.getElementById(\'crawl-speed-preset\');\n            const alertDiv = document.getElementById(\'speed-preset-alert-text\');\n\n            if (houseMin === 8.0 && houseMax === 15.0 && pageMin === 20.0 && pageMax === 40.0) {\n                presetSelect.value = \'safe\';\n                alertDiv.innerHTML = `<strong>🟢 Chế độ An toàn (Stealth Mode) đang bật:</strong> Nghỉ ngẫu nhiên 8 - 15 giây giữa các căn và 20 - 40 giây khi chuyển trang. An toàn tuyệt đối, giả lập 100% người dùng thực tế.`;\n            } else if (houseMin === 3.0 && houseMax === 6.0 && pageMin === 5.0 && pageMax === 10.0) {\n                presetSelect.value = \'optimal\';\n                alertDiv.innerHTML = `<strong>🟡 Chế độ Tối ưu (Fast & Safe) đang bật:</strong> Nghỉ ngẫu nhiên 3 - 6 giây giữa các căn và 5 - 10 giây khi chuyển trang. Tăng tốc độ cào ~2.5 lần nhưng vẫn bảo đảm an toàn chống chặn Cookie.`;\n            } else if (houseMin === 1.5 && houseMax === 3.0 && pageMin === 3.0 && pageMax === 5.0) {\n                presetSelect.value = \'turbo\';\n                alertDiv.innerHTML = `<strong>🔴 Chế độ Siêu tốc (Turbo Mode) đang bật:</strong> Nghỉ ngẫu nhiên 1.5 - 3 giây giữa các căn và 3 - 5 giây khi chuyển trang. Tốc độ cào cực nhanh (~6 lần) nhưng hãy lưu ý IP hoặc Cookie có thể nhanh hết hạn hơn.`;\n            } else {\n                presetSelect.value = \'custom\';\n                alertDiv.innerHTML = `<strong>⚙️ Chế độ Tùy chỉnh đang bật:</strong> Thời gian chờ sẽ dựa trên các thông số cấu hình cụ thể do bạn thiết lập ở bảng bên phải.`;\n            }\n        }\n\n        function fetchConfig() {\n            fetch(\'/api/config\')\n                .then(res => res.json())\n                .then(data => {\n                    if (data.status === \'success\') {\n                        const cfg = data.config;\n                        document.getElementById(\'cfg-sheet-id\').value = cfg.sheet_id || \'\';\n                        document.getElementById(\'cfg-drive-folder\').value = cfg.drive_folder_id || \'\';\n                        document.getElementById(\'cfg-openai-key\').value = cfg.openai_api_key || \'\';\n                        document.getElementById(\'cfg-openai-prompt\').value = cfg.openai_system_prompt || \'\';\n                        document.getElementById(\'crawl-url\').value = cfg.search_url || \'\';\n                        document.getElementById(\'crawl-district\').value = cfg.target_district !== undefined ? cfg.target_district : \'\';\n                        document.getElementById(\'crawl-limit\').value = cfg.crawler_limit !== undefined ? cfg.crawler_limit : 5;\n                        document.getElementById(\'crawl-start-page\').value = cfg.crawler_start_page || 1;\n                        \n                        document.getElementById(\'cfg-delay-house-min\').value = cfg.delay_house_min !== undefined ? cfg.delay_house_min : 3.0;\n                        document.getElementById(\'cfg-delay-house-max\').value = cfg.delay_house_max !== undefined ? cfg.delay_house_max : 6.0;\n                        document.getElementById(\'cfg-delay-page-min\').value = cfg.delay_page_min !== undefined ? cfg.delay_page_min : 5.0;\n                        document.getElementById(\'cfg-delay-page-max\').value = cfg.delay_page_max !== undefined ? cfg.delay_page_max : 10.0;\n                        \n                        detectAndSetPresetDropdown();\n                        \n                        currentFiltersConfig = cfg.json_ui_filters || [];\n                        renderDynamicFiltersTable();\n                    }\n                });\n        }\n\n        function saveConfig() {\n            const payload = {\n                sheet_id: document.getElementById(\'cfg-sheet-id\').value.stripOrEmpty(),\n                drive_folder_id: document.getElementById(\'cfg-drive-folder\').value.stripOrEmpty(),\n                openai_api_key: document.getElementById(\'cfg-openai-key\').value.stripOrEmpty(),\n                openai_system_prompt: document.getElementById(\'cfg-openai-prompt\').value.trim(),\n                search_url: document.getElementById(\'crawl-url\').value.stripOrEmpty(),\n                target_district: document.getElementById(\'crawl-district\').value,\n                crawler_limit: document.getElementById(\'crawl-limit\').value.trim() === "" ? 0 : (parseInt(document.getElementById(\'crawl-limit\').value) || 0),\n                crawler_start_page: parseInt(document.getElementById(\'crawl-start-page\').value) || 1,\n                delay_house_min: parseFloat(document.getElementById(\'cfg-delay-house-min\').value) || 3.0,\n                delay_house_max: parseFloat(document.getElementById(\'cfg-delay-house-max\').value) || 6.0,\n                delay_page_min: parseFloat(document.getElementById(\'cfg-delay-page-min\').value) || 5.0,\n                delay_page_max: parseFloat(document.getElementById(\'cfg-delay-page-max\').value) || 10.0\n            };\n\n            fetch(\'/api/config\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify(payload)\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(\'✅ Đã lưu cấu hình hệ thống thành công!\', \'green\');\n                }\n            });\n        }\n\n        String.prototype.stripOrEmpty = function() {\n            return this.trim();\n        };\n\n        // ==========================================\n        // SIDEBAR LISTING\n        // ==========================================\n        let selectedListingIds = [];\n\n        function setSidebarStatus(status) {\n            sidebarStatus = status;\n            // Active UI tabs\n            document.querySelectorAll(\'.sidebar-tab\').forEach(tab => {\n                tab.classList.remove(\'active\');\n                if (tab.getAttribute(\'data-status\') === status) {\n                    tab.classList.add(\'active\');\n                }\n            });\n            \n            // Clear selection when switching tabs\n            selectedListingIds = [];\n            updateBulkActionVisibility();\n            \n            fetchListings();\n        }\n\n        function toggleListingSelect(tkId, element) {\n            if (element.checked) {\n                if (!selectedListingIds.includes(tkId)) {\n                    selectedListingIds.push(tkId);\n                }\n            } else {\n                selectedListingIds = selectedListingIds.filter(id => id !== tkId);\n            }\n            updateBulkSelectCount();\n        }\n\n        function updateBulkSelectCount() {\n            const countSpan = document.getElementById(\'bulk-select-count\');\n            if (countSpan) {\n                countSpan.innerText = selectedListingIds.length;\n            }\n            \n            // Update master checkbox state\n            const chkAll = document.getElementById(\'chk-select-all-filtered\');\n            if (chkAll) {\n                const visibleChks = document.querySelectorAll(\'.house-select-chk\');\n                if (visibleChks.length > 0) {\n                    const allChecked = Array.from(visibleChks).every(chk => chk.checked);\n                    chkAll.checked = allChecked;\n                } else {\n                    chkAll.checked = false;\n                }\n            }\n        }\n\n        function updateBulkActionVisibility() {\n            const bulkPanel = document.getElementById(\'sidebar-bulk-actions\');\n            if (bulkPanel) {\n                if (sidebarStatus === \'raw_complete\') {\n                    bulkPanel.style.display = \'flex\';\n                } else {\n                    bulkPanel.style.display = \'none\';\n                }\n            }\n            updateBulkSelectCount();\n        }\n\n        function toggleSelectAllFiltered(masterChk) {\n            const visibleChks = document.querySelectorAll(\'.house-select-chk\');\n            visibleChks.forEach(chk => {\n                chk.checked = masterChk.checked;\n                const tkId = chk.getAttribute(\'data-id\');\n                if (masterChk.checked) {\n                    if (!selectedListingIds.includes(tkId)) {\n                        selectedListingIds.push(tkId);\n                    }\n                } else {\n                    selectedListingIds = selectedListingIds.filter(id => id !== tkId);\n                }\n            });\n            updateBulkSelectCount();\n        }\n\n        function bulkPublishSelected() {\n            if (selectedListingIds.length === 0) {\n                alert("Vui lòng chọn ít nhất 1 căn nhà để xuất bản!");\n                return;\n            }\n            \n            if (!confirm(`Bạn có chắc chắn muốn đẩy hàng loạt ${selectedListingIds.length} căn đã chọn lên Google Sheets Pool?`)) {\n                return;\n            }\n            \n            showBannerNotification(`⏳ Đang bắt đầu đẩy hàng loạt ${selectedListingIds.length} căn lên Sheets Pool...`, \'gold\');\n            \n            // Disable bulk publish button\n            const btn = document.getElementById(\'btn-bulk-publish\');\n            if (btn) btn.disabled = true;\n            \n            // Call API bulk-publish\n            fetch(\'/api/listings/bulk-publish\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify({ ids: selectedListingIds })\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (btn) btn.disabled = false;\n                if (data.status === \'success\') {\n                    const successCount = data.success_count;\n                    const totalCount = data.total_count;\n                    showBannerNotification(`🎉 ĐÃ ĐẨY THÀNH CÔNG ${successCount}/${totalCount} căn lên Sheets Pool!`, \'green\');\n                    \n                    // Reset selection\n                    selectedListingIds = [];\n                    fetchListings();\n                } else {\n                    alert(\'Lỗi xuất bản hàng loạt: \' + data.message);\n                }\n            })\n            .catch(err => {\n                if (btn) btn.disabled = false;\n                alert(\'Không thể kết nối máy chủ để xuất bản hàng loạt: \' + err);\n            });\n        }\n\n        function getTkIdFromSearch(query) {\n            if (!query) return null;\n            query = query.trim();\n            \n            // 1. Check if it contains a UUID anywhere (standard 36-char format with hyphens)\n            const uuidRegex = /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i;\n            const uuidMatch = query.match(uuidRegex);\n            if (uuidMatch) {\n                return uuidMatch[0];\n            }\n            \n            // 2. Check if it is a URL containing /Detail/(\\d+)\n            const detailRegex = /\\/Detail\\/(\\d+)/i;\n            const detailMatch = query.match(detailRegex);\n            if (detailMatch) {\n                return detailMatch[1];\n            }\n            \n            // 3. Fallback: split by slash and get the last non-empty segment\n            const parts = query.split(\'/\').map(p => p.trim()).filter(p => p);\n            if (parts.length > 0) {\n                const lastSegment = parts[parts.length - 1].split(\'?\')[0].trim();\n                if (lastSegment) return lastSegment;\n            }\n            \n            return null;\n        }\n\n        function fetchListings() {\n            const search = document.getElementById(\'sidebar-search\').value;\n            const quan = document.getElementById(\'filter-quan\').value;\n            const duong = document.getElementById(\'filter-duong\').value;\n            const sonha = document.getElementById(\'filter-sonha\').value;\n            \n            // Show loading spinner\n            const spinner = document.getElementById(\'search-spinner\');\n            if (spinner) spinner.style.display = \'inline-block\';\n            \n            let url = `/api/listings?status=${sidebarStatus}`;\n            if (search) {\n                url += `&search=${encodeURIComponent(search)}`;\n            }\n            if (quan) {\n                url += `&quan=${encodeURIComponent(quan)}`;\n            }\n            if (duong) {\n                url += `&duong=${encodeURIComponent(duong)}`;\n            }\n            if (sonha) {\n                url += `&so_nha=${encodeURIComponent(sonha)}`;\n            }\n\n            fetch(url)\n                .then(res => res.json())\n                .then(data => {\n                    if (spinner) spinner.style.display = \'none\';\n                    const listContainer = document.getElementById(\'listings-list\');\n                    listContainer.innerHTML = \'\';\n                    const listings = data.listings || [];\n                    \n                    // Cập nhật số lượng đếm trên các Tab trạng thái ở Sidebar\n                    const counts = data.status_counts || { raw_text: 0, raw_complete: 0, published: 0, crawl_failed: 0, missing_raw_json: 0 };\n                    const tabTextMap = {\n                        raw_text: `Chờ di cư ảnh (${counts.raw_text})`,\n                        raw_complete: `Chờ biên tập (${counts.raw_complete})`,\n                        published: `Đã xuất bản (${counts.published})`,\n                        missing_raw_json: `Thiếu JSON (${counts.missing_raw_json || 0})`,\n                        crawl_failed: `Lỗi cào (${counts.crawl_failed || 0})`\n                    };\n                    document.querySelectorAll(\'.sidebar-tab\').forEach(tab => {\n                        const status = tab.getAttribute(\'data-status\');\n                        if (tabTextMap[status]) {\n                            tab.innerText = tabTextMap[status];\n                        }\n                    });\n\n                    // Update bulk actions visibility in case counts changed\n                    updateBulkActionVisibility();\n\n                    if (listings.length === 0) {\n                        const tkId = getTkIdFromSearch(search);\n                        if (tkId) {\n                            listContainer.innerHTML = `<div style="text-align:center; padding:20px; font-size:12px; color:var(--text-muted);"><p>Đang kiểm tra căn [${tkId}]...</p></div>`;\n                            fetch(`/api/listings/${tkId}`)\n                                .then(res => {\n                                    if (res.status === 404) {\n                                        listContainer.innerHTML = `\n                                            <div style="text-align:center; padding:20px 10px; font-size:12px; color:var(--text-muted);">\n                                                <p>Căn này chưa có trong database cục bộ.</p>\n                                                <button class="btn" style="width:100%; background:var(--accent-gold); color:#000; font-weight:bold; margin-top:10px; padding: 8px;" onclick="recrawlNewListing(\'${tkId}\')">\n                                                    ➕ Cào mới căn [${tkId}]\n                                                </button>\n                                            </div>\n                                        `;\n                                    } else if (res.ok) {\n                                        return res.json();\n                                    }\n                                })\n                                .then(detailData => {\n                                    if (detailData && detailData.status === \'success\') {\n                                        const house = detailData.listing;\n                                        const statusLabel = house.status === \'raw_text\' ? \'Chờ di cư ảnh\' : (house.status === \'raw_complete\' ? \'Chờ biên tập\' : \'Đã xuất bản\');\n                                        listContainer.innerHTML = `\n                                            <div style="text-align:center; padding:20px 10px; font-size:12px; color:var(--text-muted);">\n                                                <p>Căn [${tkId}] đã tồn tại trong danh mục <b>${statusLabel}</b>.</p>\n                                                <button class="btn" style="width:100%; background:rgba(59, 130, 246, 0.2); border:1px solid #3b82f6; color:#60a5fa; font-weight:bold; margin-top:10px; padding: 8px;" onclick="setSidebarStatus(\'${house.status}\'); selectListing(\'${tkId}\');">\n                                                    👁️ Xem căn này\n                                                </button>\n                                            </div>\n                                        `;\n                                    }\n                                })\n                                .catch(err => {\n                                    listContainer.innerHTML = `<div style="text-align:center; padding:30px; font-size:12px; color:var(--text-muted);">Không tìm thấy căn nào...</div>`;\n                                });\n                        } else {\n                            listContainer.innerHTML = `<div style="text-align:center; padding:30px; font-size:12px; color:var(--text-muted);">Không tìm thấy căn nào...</div>`;\n                        }\n                        return;\n                    }\n\n                    listings.forEach(house => {\n                        const countImages = house.raw_images_tk ? house.raw_images_tk.length : 0;\n                        const isCurated = house.curated_config ? \'✓ Đã tag\' : \'Chưa tag\';\n                        const address = `${house.Ngo_So_nha || \'\'} ${house.Duong || \'\'}, P.${house.Phuong || \'\'}, Q.${house.Quan || \'\'}`;\n\n                        const card = document.createElement(\'div\');\n                        card.className = `house-card ${activeListingId === house.tk_id ? \'active\' : \'\'}`;\n                        card.onclick = () => selectListing(house.tk_id);\n\n                        const isChecked = selectedListingIds.includes(house.tk_id) ? \'checked\' : \'\';\n                        const checkboxHTML = sidebarStatus === \'raw_complete\' ? `\n                            <input type="checkbox" class="house-select-chk" data-id="${house.tk_id}" ${isChecked} onclick="event.stopPropagation(); toggleListingSelect(\'${house.tk_id}\', this)" style="cursor: pointer; width: 14px; height: 14px; margin-right: 6px;">\n                        ` : \'\';\n\n                        let badgeClass = house.status;\n                        let badgeText = house.status || \'N/A\';\n                        if (house.status === \'raw_text\') {\n                            badgeClass = \'raw_text\';\n                            badgeText = \'Chờ Drive\';\n                        } else if (house.status === \'raw_complete\') {\n                            badgeClass = \'raw_complete\';\n                            badgeText = \'Chờ biên tập\';\n                        } else if (house.status === \'published\') {\n                            badgeClass = \'published\';\n                            badgeText = \'Published\';\n                        } else if (house.status && house.status.startsWith(\'crawl_failed\')) {\n                            badgeClass = \'crawl_failed\';\n                            badgeText = \'Lỗi cào\';\n                        }\n\n                        card.innerHTML = `\n                            <div class="house-card-header" style="display: flex; align-items: center;">\n                                ${checkboxHTML}\n                                <span class="house-id" style="${sidebarStatus === \'raw_complete\' ? \'margin-left: 2px;\' : \'\'}">${house.tk_id}</span>\n                                <span class="status-badge badge-${badgeClass}">${badgeText}</span>\n                            </div>\n                            <div class="house-title">${house.Mo_ta_chi_tiet || house.Noi_dung_chinh || \'Không có mô tả\'}</div>\n                            <div class="house-meta">\n                                <span>📍 Q.${house.Quan}</span>\n                                <span>🖼️ ${countImages} ảnh</span>\n                                <span style="margin-left:auto; color:${house.curated_config ? \'var(--accent-green)\' : \'var(--text-muted)\'}">${isCurated}</span>\n                            </div>\n                        `;\n                        listContainer.appendChild(card);\n                    });\n                })\n                .catch(err => {\n                    console.error("Lỗi khi tải danh sách:", err);\n                    if (spinner) spinner.style.display = \'none\';\n                });\n        }\n\n        function selectListing(tkId) {\n            activeListingId = tkId;\n            // Highlight card\n            document.querySelectorAll(\'.house-card\').forEach(card => card.classList.remove(\'active\'));\n            fetchListings(); // Cập nhật class active trong render lại\n\n            // Tải chi tiết\n            fetch(`/api/listings/${tkId}`)\n                .then(res => res.json())\n                .then(data => {\n                    if (data.status === \'success\') {\n                        activeListingData = data.listing;\n                        renderEditor();\n                        // Tự chuyển sang tab Edit\n                        switchTab(\'edit-tab\');\n                    }\n                });\n        }\n\n        // ==========================================\n        // CRAWL LOGS POLLING & TRIGGER\n        // ==========================================\n        function fetchLogs() {\n            fetch(\'/api/logs\')\n                .then(res => res.json())\n                .then(data => {\n                    const term = document.getElementById(\'terminal-log\');\n                    let lines = data.logs || [];\n                    \n                    // Nếu không có log nào, hiển thị lời chào sẵn sàng để giao diện không bị trống\n                    if (lines.length === 0) {\n                        lines = [\n                            "[i] HỆ THỐNG CRAWLER ĐÃ SẴN SÀNG.",\n                            "[i] Vui lòng cập nhật Cookie Thiên Khôi và bấm \'BẮT ĐẦU CÀO TIN\' để bắt đầu..."\n                        ];\n                    }\n                    \n                    const logsSignature = lines.join(\'\\n\');\n                    // Sử dụng so sánh chữ ký chuỗi (signature) để phát hiện chính xác mọi thay đổi về nội dung log\n                    if (logsSignature !== lastLogsSignature) {\n                        lastLogsSignature = logsSignature;\n                        let html = \'\';\n                        let hasProgressUpdate = false;\n                        lines.forEach(line => {\n                            if (!line) return;\n                            let style = \'\';\n                            if (line.includes(\'[❌ LỖI]\')) style = \'color: var(--accent-red);\';\n                            else if (line.includes(\'[✅\') || line.includes(\'thành công\')) style = \'color: var(--accent-green);\';\n                            else if (line.includes(\'[⚠️\') || line.includes(\'hết hạn\')) style = \'color: var(--accent-gold);\';\n                            else if (line.includes(\'Nghỉ tàng hình\')) style = \'color: #a855f7;\'; // Tím cho delay tàng hình\n                            \n                            // Tự động kích hoạt còi cảnh báo âm thanh bíp khi phát hiện cookie hết hạn cào tin\n                            if (line.includes(\'hết hạn\') || line.includes(\'security.html\')) {\n                                triggerCookieExpiredAlert();\n                            }\n                            \n                            if (line.includes(\'lưu trang tiếp theo\')) {\n                                hasProgressUpdate = true;\n                            }\n                            \n                            html += `<div class="terminal-line" style="${style}">${escapeHtml(line)}</div>`;\n                        });\n                        term.innerHTML = html;\n                        term.scrollTop = term.scrollHeight;\n                        \n                        if (hasProgressUpdate) {\n                            fetchConfig();\n                        }\n                    }\n                })\n                .catch(err => {\n                    console.error("Lỗi đồng bộ console logs:", err);\n                });\n        }\n\n        function clearLogs() {\n            fetch(\'/api/logs/clear\', { method: \'POST\' })\n                .then(() => {\n                    document.getElementById(\'terminal-log\').innerHTML = \'\';\n                });\n        }\n\n        function startCrawl() {\n            const url = document.getElementById(\'crawl-url\').value.stripOrEmpty();\n            const district = document.getElementById(\'crawl-district\').value;\n            const limitVal = document.getElementById(\'crawl-limit\').value.trim();\n            const limit = limitVal === "" ? 0 : (parseInt(limitVal) || 0);\n            const start_page = parseInt(document.getElementById(\'crawl-start-page\').value) || 1;\n\n            if (!url) {\n                alert(\'Vui lòng điền URL danh sách Quận Thiên Khôi để cào.\');\n                return;\n            }\n\n            // Xóa logs cũ\n            clearLogs();\n            \n            // Lưu lại cấu hình hiện tại trước khi cào\n            saveConfig();\n\n            fetch(\'/api/crawl\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify({ url, district, limit, start_page })\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(\'🚀 Tiến trình cào ngầm đã được kích hoạt! Hãy theo dõi terminal bên dưới.\', \'gold\');\n                } else {\n                    alert(\'Không khởi động được tiến trình: \' + data.message);\n                }\n            });\n        }\n\n        function startMigration() {\n            const limit = parseInt(document.getElementById(\'migrate-limit\').value) || 10;\n            const fill = document.getElementById(\'migrate-progress-fill\');\n            const wrapper = document.getElementById(\'migrate-progress-wrapper\');\n            \n            wrapper.style.display = \'block\';\n            fill.style.width = \'10%\'; // Mock loading start\n\n            fetch(\'/api/migrate\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify({ limit })\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(\'🖼️ Tiến trình di cư Drive đang chạy ngầm. Vui lòng xem logs cào tin ở Tab Cào.\', \'gold\');\n                    // Mock loop check\n                    let w = 10;\n                    const interval = setInterval(() => {\n                        w += 15;\n                        if (w > 100) {\n                            w = 100;\n                            clearInterval(interval);\n                            setTimeout(() => { wrapper.style.display = \'none\'; }, 2000);\n                        }\n                        fill.style.width = `${w}%`;\n                    }, 3000);\n                }\n            });\n        }\n\n        // ==========================================\n        // COOKIE CACHE DIALOG\n        // ==========================================\n        function openCookieModal() {\n            document.getElementById(\'cookie-modal\').style.display = \'flex\';\n        }\n\n        function closeCookieModal() {\n            document.getElementById(\'cookie-modal\').style.display = \'none\';\n        }\n\n        function saveCookieCache() {\n            const cookieVal = document.getElementById(\'user-cookie-input\').value.stripOrEmpty();\n            if (!cookieVal) {\n                alert(\'Vui lòng dán chuỗi cookie hợp lệ.\');\n                return;\n            }\n\n            showBannerNotification(\'⏳ Đang lưu và đồng bộ Cookie mới...\', \'gold\');\n\n            fetch(\'/api/cookie/save\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify({ cookie: cookieVal })\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    cookieExpiredAlerted = false; // Reset warning state!\n                    lastLogsSignature = ""; // Xóa chữ ký log cũ để không bị nhận dạng nhầm\n                    document.getElementById(\'terminal-log\').innerHTML = ""; // Xóa trắng log hiển thị cũ tránh lặp alert\n                    showBannerNotification(\'🔑 Đã lưu và đồng bộ Cookie thành công!\', \'green\');\n                    closeCookieModal();\n                } else {\n                    alert(\'Lỗi lưu cookie: \' + data.message);\n                }\n            })\n            .catch(err => {\n                alert(\'Lỗi kết nối lưu cookie: \' + err);\n            });\n        }\n\n        // ==========================================\n        // CURATOR IMAGE STATION & ROLE ASSIGNMENT\n        // ==========================================\n        function renderEditor() {\n            document.getElementById(\'no-listing-selected\').style.display = \'none\';\n            document.getElementById(\'editor-active\').style.display = \'block\';\n\n            const house = activeListingData;\n            \n            // Check status for crawl failure banner\n            const errorBanner = document.getElementById(\'editor-error-banner\');\n            if (errorBanner) {\n                if (house.status && house.status.startsWith(\'crawl_failed:\')) {\n                    const reasonKey = house.status.split(\':\')[1];\n                    let reasonText = "Lỗi chưa xác định";\n                    if (reasonKey === "deleted") {\n                        reasonText = "❌ Đã xóa/Không tìm thấy trên nguồn";\n                    } else if (reasonKey === "cookie_expired") {\n                        reasonText = "🔑 Cookie hết hạn / Hết phiên";\n                    } else if (reasonKey === "http_error") {\n                        reasonText = "🌐 Lỗi HTTP / Mạng kết nối";\n                    } else if (reasonKey === "exception") {\n                        reasonText = "⚠️ Lỗi xử lý dữ liệu (Exception)";\n                    } else if (reasonKey === "cookie_invalid") {\n                        reasonText = "🔑 Cookie không hợp lệ";\n                    }\n                    document.getElementById(\'editor-error-reason\').innerText = reasonText;\n                    errorBanner.style.display = \'block\';\n                } else {\n                    errorBanner.style.display = \'none\';\n                }\n            }\n            \n            // Text fields\n            document.getElementById(\'edit-tieu-de-public\').value = house.Tieu_de_Public || \'\';\n            document.getElementById(\'edit-mo-ta-public\').value = house.Mo_ta_Public || \'\';\n            document.getElementById(\'edit-ma-khang-ngo\').value = house.Ma_Khang_Ngo_ID || house.tk_id || \'\';\n            document.getElementById(\'edit-gia-public\').value = house.Gia_Public || house.Gia_chao || \'\';\n            document.getElementById(\'edit-phan-loai-hem\').value = house.Phan_loai_Hem || \'Hẻm xe hơi\';\n            document.getElementById(\'edit-duong-truoc-nha\').value = house.Duong_truoc_nha_m || \'\';\n            document.getElementById(\'edit-mat-tien\').value = house.Mat_Tien || \'\';\n            document.getElementById(\'edit-chieu-dai\').value = house.Chieu_dai || \'\';\n            document.getElementById(\'edit-so-phong-ngu\').value = house.So_phong_ngu || \'\';\n            document.getElementById(\'edit-so-nha-ve-sinh\').value = house.So_nha_ve_sinh || \'\';\n            document.getElementById(\'edit-danh-gia\').value = house.Danh_gia_Admin || \'\';\n            document.getElementById(\'edit-ngu-tret\').value = house.Ngu_tret_Admin || \'\';\n            document.getElementById(\'edit-chdv\').value = house.CHDV_Admin || \'\';\n            document.getElementById(\'edit-tinh-trang-nha\').value = house.Tinh_trang_nha || \'Bình thường\';\n            document.getElementById(\'edit-phuong-cu-ai\').value = house.Phuong_cu_AI_ || \'\';\n            \n            // Địa chỉ thực tế\n            document.getElementById(\'edit-ngo-so-nha\').value = house.Ngo_So_nha || \'\';\n            document.getElementById(\'edit-quan\').value = house.Quan || \'\';\n            document.getElementById(\'edit-phuong\').value = house.Phuong || \'\';\n            document.getElementById(\'edit-duong\').value = house.Duong || \'\';\n            \n            // Tự động tính toán Mã Khang Ngô tức thời khi tải thông tin căn nhà\n            updateMaKhangNgoLive();\n            \n            // Tự động kích hoạt AI Biên tập nếu chưa có Tiêu đề hoặc Mô tả Public\n            // Đảm bảo có debouncing 300ms để Trang click nhanh danh sách không bị lặp request gọi API\n            if (window.autoAiTimeoutId) {\n                clearTimeout(window.autoAiTimeoutId);\n            }\n            \n            const tieuDePublicVal = (house.Tieu_de_Public || "").toString().trim();\n            const moTaPublicVal = (house.Mo_ta_Public || "").toString().trim();\n            \n            if (tieuDePublicVal === "" || moTaPublicVal === "") {\n                window.autoAiTimeoutId = setTimeout(() => {\n                    addLogMessage(`[🤖 AUTO-AI] Phát hiện căn ${house.tk_id} chưa được biên dịch Public. Tự động chạy AI Biên tập...`);\n                    runAiCuration();\n                }, 300);\n            }\n\n            // Gán dữ liệu cào gốc chỉ đọc\n            document.getElementById(\'raw-ma-hang\').innerText = house.tk_id || \'Trống\';\n            document.getElementById(\'raw-gia-chao\').innerText = house.Gia_chao || \'Trống\';\n            document.getElementById(\'raw-tinh-thanh\').innerText = house.T_nh || house.Tinh || \'Trống\';\n            document.getElementById(\'raw-quan-huyen\').innerText = house.Quan || \'Trống\';\n            document.getElementById(\'raw-phuong-xa\').innerText = house.Phuong || \'Trống\';\n            document.getElementById(\'raw-so-nha\').innerText = house.Ngo_So_nha || \'Trống\';\n            document.getElementById(\'raw-duong-pho\').innerText = house.Duong || \'Trống\';\n            \n            document.getElementById(\'raw-dt-thuc-te\').innerText = house.DT_Thuc_te || \'Trống\';\n            document.getElementById(\'raw-dt-tren-so\').innerText = house.DT_Tren_so || \'Trống\';\n            document.getElementById(\'raw-mat-tien\').innerText = house.Mat_Tien || \'Trống\';\n            // Hiển thị chiều dài cào được, để trống nếu không có\n            document.getElementById(\'raw-chieu-dai\').innerText = house.Chieu_dai || \'\';\n            \n            document.getElementById(\'raw-duong-truoc-nha\').innerText = house.Duong_truoc_nha_m || \'Trống\';\n            document.getElementById(\'raw-so-tang\').innerText = house.So_Tang || \'Trống\';\n            document.getElementById(\'raw-so-phong-ngu\').innerText = house.So_phong_ngu || \'Trống\';\n            document.getElementById(\'raw-so-nha-ve-sinh\').innerText = house.So_nha_ve_sinh || \'Trống\';\n            document.getElementById(\'raw-huong\').innerText = house.Huong || \'Trống\';\n            \n            document.getElementById(\'raw-ten-dau-chu\').innerText = house.Ten_Dau_Chu_Hop_dong || \'Trống\';\n            document.getElementById(\'raw-dt-dau-chu\').innerText = house.Dien_thoai_Dau_Chu || \'Trống\';\n            \n            // Link Facebook Đầu Chủ\n            const fbLink = document.getElementById(\'raw-link-fb\');\n            const noFb = document.getElementById(\'raw-no-fb\');\n            if (house.Diem_Facebook) {\n                fbLink.href = house.Diem_Facebook;\n                fbLink.style.display = \'inline-block\';\n                noFb.style.display = \'none\';\n            } else {\n                fbLink.href = "#";\n                fbLink.style.display = \'none\';\n                noFb.style.display = \'inline\';\n            }\n            \n            document.getElementById(\'raw-noi-dung-chinh\').innerText = house.Noi_dung_chinh || \'Không có dữ liệu\';\n            document.getElementById(\'raw-mo-ta-chi-tiet\').innerText = house.Mo_ta_chi_tiet || \'Không có dữ liệu\';\n\n            // Xử lý hình ảnh\n            // Nếu có curated_config thì dùng, nếu không thì tự tạo mảng mặc định từ raw_drive_images\n            const rawImgs = house.raw_drive_images && house.raw_drive_images.length > 0 ? house.raw_drive_images : house.raw_images_tk;\n            const originalImgs = house.raw_images_tk || [];\n            \n            if (house.curated_config && house.curated_config.images && house.curated_config.images.length > 0) {\n                imagesConfig = house.curated_config.images;\n                // Merge thêm ảnh mới nếu có phát sinh cào thêm\n                rawImgs.forEach((url, i) => {\n                    if (!imagesConfig.some(item => item.url === url)) {\n                        const origUrl = originalImgs[i] || \'\';\n                        let role = \'Ẩn\';\n                        if (origUrl) {\n                            if (origUrl === house.So_do_thua_dat_1 || origUrl === house.So_do_thua_dat_2) {\n                                role = \'Sơ đồ\';\n                            } else if (origUrl === house.Hinh_Mat_Tien) {\n                                role = \'Mặt tiền\';\n                            } else if (origUrl === house.Hinh_Nhan_Dien) {\n                                role = \'Bìa\';\n                            }\n                        }\n                        imagesConfig.push({ url: url, role: role });\n                    }\n                });\n            } else {\n                // Tạo config mặc định và tự động phát hiện vai trò dựa trên so sánh link gốc!\n                imagesConfig = rawImgs.map((url, i) => {\n                    const origUrl = originalImgs[i] || \'\';\n                    let role = \'Ẩn\';\n                    \n                    if (origUrl) {\n                        if (origUrl === house.So_do_thua_dat_1 || origUrl === house.So_do_thua_dat_2) {\n                            role = \'Sơ đồ\';\n                        } else if (origUrl === house.Hinh_Mat_Tien) {\n                            role = \'Mặt tiền\';\n                        } else if (origUrl === house.Hinh_Nhan_Dien) {\n                            role = \'Bìa\';\n                        }\n                    }\n                    \n                    return { url: url, role: role };\n                });\n            }\n\n            renderImageGrid();\n        }\n\n        function sortImagesConfig() {\n            // Sắp xếp: Không phải \'Ẩn\' lên trên đầu, \'Ẩn\' xuống dưới cùng\n            imagesConfig.sort((a, b) => {\n                const aIsHidden = a.role === \'Ẩn\';\n                const bIsHidden = b.role === \'Ẩn\';\n                if (aIsHidden && !bIsHidden) return 1;\n                if (!aIsHidden && bIsHidden) return -1;\n                return 0; // Giữ nguyên thứ tự tương đối\n            });\n        }\n\n        function renderImageGrid() {\n            // Sắp xếp tự động trước khi render\n            sortImagesConfig();\n            \n            const grid = document.getElementById(\'curator-image-grid\');\n            grid.innerHTML = \'\';\n\n            imagesConfig.forEach((item, index) => {\n                const card = document.createElement(\'div\');\n                card.className = \'image-card\';\n\n                // Display role text\n                const roleLabels = {\n                    \'Bìa\': \'Nền\',\n                    \'Mặt tiền\': \'Mặt tiền\',\n                    \'Sơ đồ\': \'Sơ đồ\',\n                    \'Hẻm\': \'Hẻm\',\n                    \'Nội thất\': \'Nội thất\',\n                    \'Ẩn\': \'Ẩn/Bỏ qua\'\n                };\n\n                const labelStyle = {\n                    \'Bìa\': \'background: var(--accent-green); color:#000;\',\n                    \'Mặt tiền\': \'background: var(--accent-red); color:#fff;\',\n                    \'Sơ đồ\': \'background: var(--accent-gold); color:#000;\',\n                    \'Hẻm\': \'background: var(--accent-blue); color:#fff;\',\n                    \'Nội thất\': \'background: var(--accent-cyan); color:#000;\',\n                    \'Ẩn\': \'background: var(--accent-slate); color:#fff;\'\n                };\n\n                const isDimmed = item.role === \'Ẩn\' || item.visible === false;\n                const cardStyle = isDimmed ? \'opacity: 0.4;\' : \'\';\n\n                card.innerHTML = `\n                    <div class="image-wrapper" style="${cardStyle} position: relative;">\n                        <img src="${item.url}" onerror="this.onerror=null; this.src=\'data:image/svg+xml;utf8,<svg xmlns=\\\'http://www.w3.org/2000/svg\\\' width=\\\'300\\\' height=\\\'200\\\' viewBox=\\\'0 0 300 200\\\'><rect width=\\\'100%\\\' height=\\\'100%\\\' fill=\\\'%231e293b\\\'/><text x=\\\'50%\\\' y=\\\'50%\\\' dominant-baseline=\\\'middle\\\' text-anchor=\\\'middle\\\' font-family=\\\'sans-serif\\\' font-size=\\\'14\\\' fill=\\\'%2394a3b8\\\'>Ảnh lỗi hoặc Đang di cư...</text></svg>\';">\n                        <span class="image-role-badge" style="${labelStyle[item.role]}">${roleLabels[item.role]}</span>\n                        <div class="visibility-checkbox-container" style="position: absolute; bottom: 5px; right: 5px; background: rgba(0,0,0,0.7); padding: 2px 6px; border-radius: 4px; display: flex; align-items: center; gap: 4px; z-index: 10;">\n                            <input type="checkbox" id="visible-check-${index}" ${item.visible !== false ? \'checked\' : \'\'} onchange="toggleImageVisibility(${index}, this.checked)" style="cursor: pointer; width: 14px; height: 14px; margin: 0;">\n                            <label for="visible-check-${index}" style="color: #fff; font-size: 11px; font-weight: bold; cursor: pointer; margin: 0;">Hiện</label>\n                        </div>\n                    </div>\n                    <div class="image-controls">\n                        <div class="role-btn-group">\n                            <span class="role-btn role-bia ${item.role === \'Bìa\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Bìa\')">Nền</span>\n                            <span class="role-btn role-mt ${item.role === \'Mặt tiền\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Mặt tiền\')">MT</span>\n                            <span class="role-btn role-sodo ${item.role === \'Sơ đồ\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Sơ đồ\')">Sơ đồ</span>\n                        </div>\n                        <div class="role-btn-group">\n                            <span class="role-btn role-hem ${item.role === \'Hẻm\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Hẻm\')">Hẻm</span>\n                            <span class="role-btn role-public ${item.role === \'Nội thất\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Nội thất\')">N.Thất</span>\n                            <span class="role-btn role-an ${item.role === \'Ẩn\' ? \'active\' : \'\'}" onclick="assignImageRole(${index}, \'Ẩn\')">Ẩn</span>\n                        </div>\n                        <div class="order-btn-group">\n                            <button class="order-btn" onclick="moveImage(${index}, -1)" ${index === 0 ? \'disabled\' : \'\'}>◀ Trái</button>\n                            <span style="font-size:10px; color:var(--text-muted)">#${index+1}</span>\n                            <button class="order-btn" onclick="moveImage(${index}, 1)" ${index === imagesConfig.length - 1 ? \'disabled\' : \'\'}>Phải ▶</button>\n                        </div>\n                    </div>\n                `;\n                grid.appendChild(card);\n            });\n        }\n\n        function toggleImageVisibility(idx, isChecked) {\n            imagesConfig[idx].visible = isChecked;\n            renderImageGrid();\n        }\n\n        function assignImageRole(idx, role) {\n            // Nếu đổi thành Bìa (Nền)\n            if (role === \'Bìa\') {\n                // Reset Bìa (Nền) cũ về Ẩn\n                imagesConfig.forEach(item => {\n                    if (item.role === \'Bìa\') item.role = \'Ẩn\';\n                });\n                \n                // Gán vai trò Bìa cho ảnh được chọn\n                imagesConfig[idx].role = \'Bìa\';\n                imagesConfig[idx].visible = true;\n                \n                // Đổi vị trí (swap) với index 0 (Ảnh 1)\n                if (idx > 0) {\n                    const temp = imagesConfig[0];\n                    imagesConfig[0] = imagesConfig[idx];\n                    imagesConfig[idx] = temp;\n                }\n            } else if (role === \'Mặt tiền\') {\n                // Reset Mặt tiền cũ về Ẩn\n                imagesConfig.forEach(item => {\n                    if (item.role === \'Mặt tiền\') item.role = \'Ẩn\';\n                });\n                imagesConfig[idx].role = role;\n                imagesConfig[idx].visible = false;\n            } else {\n                imagesConfig[idx].role = role;\n                if (role === \'Sơ đồ\') {\n                    imagesConfig[idx].visible = false;\n                } else if (role === \'Hẻm\' || role === \'Nội thất\') {\n                    imagesConfig[idx].visible = true;\n                }\n            }\n            renderImageGrid();\n        }\n\n        function moveImage(idx, dir) {\n            const targetIdx = idx + dir;\n            if (targetIdx < 0 || targetIdx >= imagesConfig.length) return;\n            \n            // Swap\n            const temp = imagesConfig[idx];\n            imagesConfig[idx] = imagesConfig[targetIdx];\n            imagesConfig[targetIdx] = temp;\n            \n            renderImageGrid();\n        }\n\n\n\n        // ==========================================\n        // SAVE & PUBLISH CORE LOGIC\n        // ==========================================\n        function compileListingPayload() {\n            // Lọc ra các liên kết theo nhãn vai trò\n            const hinhNhanDien = imagesConfig.find(img => img.role === \'Bìa\')?.url || \'\';\n            const hinhMatTien = imagesConfig.find(img => img.role === \'Mặt tiền\')?.url || \'\';\n            const soDoImgs = imagesConfig.filter(img => img.role === \'Sơ đồ\').map(img => img.url);\n            \n            // Lọc ảnh Hẻm tuần tự đưa vào Hình Hẻm 1-10\n            const hemImgs = imagesConfig.filter(img => img.role === \'Hẻm\').map(img => img.url).slice(0, 10);\n            \n            // Điền tuần tự toàn bộ ảnh vào Ảnh 1 - Ảnh 15 bất kể role (giữ order)\n            const publicImgs = imagesConfig.map(img => img.url).slice(0, 15);\n\n            // Tìm vị trí 1-based của ảnh Nội thất và ảnh Hẻm trong chuỗi Ảnh 1-15\n            const publicIndices = [];\n            const hemIndices = [];\n            imagesConfig.slice(0, 15).forEach((img, i) => {\n                if (img.role === \'Nội thất\') {\n                    publicIndices.push(i + 1);\n                }\n                if (img.role === \'Hẻm\') {\n                    hemIndices.push(i + 1);\n                }\n            });\n\n            const anhPublicField = publicIndices.join(\',\');\n            const anhHemPublicField = hemIndices.join(\',\');\n\n            return {\n                tieu_de_public: document.getElementById(\'edit-tieu-de-public\').value,\n                mo_ta_public: document.getElementById(\'edit-mo-ta-public\').value,\n                ngo_so_nha: document.getElementById(\'edit-ngo-so-nha\').value,\n                quan: document.getElementById(\'edit-quan\').value,\n                phuong: document.getElementById(\'edit-phuong\').value,\n                duong: document.getElementById(\'edit-duong\').value,\n                ma_khang_ngo: document.getElementById(\'edit-ma-khang-ngo\').value,\n                gia_public: document.getElementById(\'edit-gia-public\').value,\n                phan_loai_hem: document.getElementById(\'edit-phan-loai-hem\').value,\n                duong_truoc_nha: document.getElementById(\'edit-duong-truoc-nha\').value,\n                mat_tien: document.getElementById(\'edit-mat-tien\').value,\n                chieu_dai: document.getElementById(\'edit-chieu-dai\').value,\n                so_phong_ngu: document.getElementById(\'edit-so-phong-ngu\').value,\n                so_nha_ve_sinh: document.getElementById(\'edit-so-nha-ve-sinh\').value,\n                danh_gia: document.getElementById(\'edit-danh-gia\').value,\n                ngu_tret: document.getElementById(\'edit-ngu-tret\').value,\n                chdv: document.getElementById(\'edit-chdv\').value,\n                tinh_trang_nha: document.getElementById(\'edit-tinh-trang-nha\').value,\n                phuong_cu_ai: document.getElementById(\'edit-phuong-cu-ai\').value,\n                \n                // Trạm ảnh\n                hinh_nhan_dien: hinhNhanDien,\n                hinh_mat_tien: hinhMatTien,\n                so_do_1: soDoImgs[0] || \'\',\n                so_do_2: soDoImgs[1] || \'\',\n                so_do_3: soDoImgs[2] || \'\',\n                so_do_4: soDoImgs[3] || \'\',\n                so_do_5: soDoImgs[4] || \'\',\n                hem_imgs: hemImgs,\n                public_imgs: publicImgs,\n                anh_public_vd_1_3_5: anhPublicField,\n                anh_hem_public_vd_1_2: anhHemPublicField,\n                \n                // Save nguyên trạng cấu hình ảnh\n                curated_config: {\n                    images: imagesConfig,\n                    Mã_Khang_Ngô__ID_: document.getElementById(\'edit-ma-khang-ngo\').value\n                }\n            };\n        }\n\n        function saveListingEdits(showNotification = true) {\n            const payload = compileListingPayload();\n            \n            return fetch(`/api/listings/${activeListingId}`, {\n                method: \'PUT\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify(payload)\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    if (showNotification) {\n                        showBannerNotification(\'💾 Đã lưu cấu hình biên tập cục bộ thành công vào SQLite!\', \'green\');\n                        \n                        // TỰ ĐỘNG XUẤT BẢN LÊN GOOGLE SHEETS POOL KHI BẤM LƯU CỤC BỘ\n                        setTimeout(() => {\n                            publishToSheets();\n                        }, 500);\n                    }\n                    // Refresh listing data\n                    fetchListings();\n                }\n            });\n        }\n\n        function publishToSheets() {\n            // Bước 1: Lưu thay đổi cục bộ trước\n            saveListingEdits(false).then(() => {\n                // Bước 2: Trigger publish lên Sheets\n                showBannerNotification(\'🚀 Đang kết nối Google Sheets Cloud và đẩy 79 cột...\', \'gold\');\n                \n                fetch(`/api/publish/${activeListingId}`, {\n                    method: \'POST\'\n                })\n                .then(res => res.json())\n                .then(data => {\n                    if (data.status === \'success\') {\n                        showBannerNotification(\'🎉 XUẤT BẢN THÀNH CÔNG trực tiếp lên Google Sheets!\', \'green\');\n                        fetchListings(); // Load lại list để đổi status badge\n                        selectListing(activeListingId); // Tải lại chi tiết\n                    } else if (data.status === \'warning\') {\n                        // Fallback show copy text\n                        showBannerNotification(\'⚠️ Lỗi Cloud. Hãy copy dòng 79 cột bên dưới để paste thủ công!\', \'yellow\');\n                        openCopierModal(data.row_data);\n                    }\n                });\n            });\n        }\n\n        function clearAllListings() {\n            if (!confirm("⚠️ CẢNH BÁO QUAN TRỌNG:\\nHành động này sẽ XÓA TOÀN BỘ tin đã cào trong SQLite và toàn bộ thư mục ảnh cục bộ!\\n\\nBạn có chắc chắn muốn xóa sạch dữ liệu cũ không?")) {\n                return;\n            }\n            if (!confirm("❗ BẠN CÓ CHẮC CHẮN 100%?\\nDữ liệu đã xóa sẽ KHÔNG THỂ KHÔI PHỤC lại được.")) {\n                return;\n            }\n            \n            showBannerNotification(\'🧹 Đang tiến hành xóa toàn bộ dữ liệu cào cũ...\', \'gold\');\n            \n            fetch(\'/api/listings/clear\', {\n                method: \'POST\'\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(\'✅ Đã xóa sạch dữ liệu cũ và hình ảnh thành công!\', \'green\');\n                    // Reset active listing view\n                    activeListingId = null;\n                    activeListingData = null;\n                    document.getElementById(\'no-listing-selected\').style.display = \'block\';\n                    document.getElementById(\'editor-active\').style.display = \'none\';\n                    fetchListings();\n                } else {\n                    alert(\'Lỗi khi xóa dữ liệu: \' + data.message);\n                }\n            })\n            .catch(err => {\n                alert(\'Không thể kết nối máy chủ để xóa dữ liệu: \' + err);\n            });\n        }\n\n        function deleteActiveListing() {\n            if (!activeListingId) return;\n            \n            if (!confirm(`🗑️ Bạn có chắc chắn muốn XÓA căn nhà [${activeListingId}] này khỏi cơ sở dữ liệu SQLite cục bộ không?\\n\\nẢnh cục bộ của căn này cũng sẽ bị xóa.`)) {\n                return;\n            }\n            \n            showBannerNotification(`🧹 Đang xóa căn ${activeListingId}...`, \'gold\');\n            \n            fetch(`/api/listings/${activeListingId}`, {\n                method: \'DELETE\'\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(`✅ Đã xóa thành công căn ${activeListingId}!`, \'green\');\n                    // Reset active listing view\n                    activeListingId = null;\n                    activeListingData = null;\n                    document.getElementById(\'no-listing-selected\').style.display = \'block\';\n                    document.getElementById(\'editor-active\').style.display = \'none\';\n                    fetchListings();\n                } else {\n                    alert(\'Lỗi khi xóa căn: \' + data.message);\n                }\n            })\n            .catch(err => {\n                alert(\'Không thể kết nối máy chủ để xóa căn: \' + err);\n            });\n        }\n\n        function recrawlActiveListing() {\n            if (!activeListingId) return;\n            \n            if (!confirm(`🔄 Bạn có chắc chắn muốn CÀO LẠI căn nhà [${activeListingId}] này không?\\n\\nHành động này sẽ tải lại dữ liệu mới nhất từ Thiên Khôi và GHI ĐÈ lên các trường dữ liệu hiện tại.`)) {\n                return;\n            }\n            \n            showBannerNotification(`🔄 Đang cào lại dữ liệu căn ${activeListingId}...`, \'gold\');\n            \n            fetch(`/api/listings/${activeListingId}/recrawl`, {\n                method: \'POST\'\n            })\n            .then(async res => {\n                if (!res.ok) {\n                    const text = await res.text();\n                    let errMsg = `HTTP ${res.status}`;\n                    try {\n                        const errJson = JSON.parse(text);\n                        if (errJson && errJson.message) {\n                            errMsg = errJson.message;\n                        }\n                    } catch (e) {\n                        // Response is not JSON, might be a 500 error page\n                        if (text && text.length < 200) {\n                            errMsg += `: ${text}`;\n                        } else {\n                            errMsg += ` (Lỗi hệ thống phía Server)`;\n                        }\n                    }\n                    throw new Error(errMsg);\n                }\n                return res.json();\n            })\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(`✅ Đã cào lại thành công căn nhà ${activeListingId}!`, \'green\');\n                    // Tải lại dữ liệu chi tiết và cập nhật giao diện\n                    activeListingData = data.listing;\n                    renderEditor();\n                } else {\n                    alert(\'Lỗi khi cào lại căn nhà: \' + data.message);\n                    fetchListings();\n                    loadTroubleList();\n                    // Load lại chi tiết từ DB để hiển thị trạng thái lỗi cào\n                    fetch(`/api/listings/${activeListingId}`)\n                        .then(res => res.json())\n                        .then(detailData => {\n                            if (detailData && detailData.status === \'success\') {\n                                activeListingData = detailData.listing;\n                                renderEditor();\n                            }\n                        })\n                        .catch(e => console.error("Lỗi khi tải chi tiết căn nhà:", e));\n                }\n            })\n            .catch(err => {\n                alert(\'Không thể kết nối máy chủ để cào lại căn nhà: \' + err.message);\n                fetchListings();\n                loadTroubleList();\n                // Load lại chi tiết từ DB để hiển thị trạng thái lỗi cào\n                fetch(`/api/listings/${activeListingId}`)\n                    .then(res => res.json())\n                    .then(detailData => {\n                        if (detailData && detailData.status === \'success\') {\n                            activeListingData = detailData.listing;\n                            renderEditor();\n                        }\n                    })\n                    .catch(e => console.error("Lỗi khi tải chi tiết căn nhà:", e));\n            });\n        }\n\n        function recrawlNewListing(tkId) {\n            showBannerNotification(`🔄 Đang cào mới căn nhà [${tkId}] từ Thiên Khôi...`, \'gold\');\n            \n            fetch(`/api/listings/${tkId}/recrawl`, {\n                method: \'POST\'\n            })\n            .then(async res => {\n                if (!res.ok) {\n                    const text = await res.text();\n                    let errMsg = `HTTP ${res.status}`;\n                    try {\n                        const errJson = JSON.parse(text);\n                        if (errJson && errJson.message) {\n                            errMsg = errJson.message;\n                        }\n                    } catch (e) {\n                        if (text && text.length < 200) {\n                            errMsg += `: ${text}`;\n                        } else {\n                            errMsg += ` (Lỗi hệ thống phía Server)`;\n                        }\n                    }\n                    throw new Error(errMsg);\n                }\n                return res.json();\n            })\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(`✅ ${data.message || \'Cào mới thành công!\'}`, \'green\');\n                    \n                    // Chuyển tab sidebar sang trạng thái của căn vừa cào\n                    const listingStatus = data.listing.status || \'raw_text\';\n                    sidebarStatus = listingStatus;\n                    document.querySelectorAll(\'.sidebar-tab\').forEach(tab => {\n                        tab.classList.remove(\'active\');\n                        if (tab.getAttribute(\'data-status\') === listingStatus) {\n                            tab.classList.add(\'active\');\n                        }\n                    });\n                    \n                    selectedListingIds = [];\n                    updateBulkActionVisibility();\n                    \n                    // Chọn và hiển thị căn nhà vừa cào\n                    selectListing(tkId);\n                } else {\n                    alert(\'Lỗi khi cào mới căn nhà: \' + data.message);\n                }\n            })\n            .catch(err => {\n                alert(\'Không thể kết nối máy chủ để cào mới căn nhà: \' + err.message);\n            });\n        }\n\n        // ==========================================\n        // FALLBACK COPIER MODAL\n        // ==========================================\n        function openCopierModal(rowData) {\n            const modal = document.getElementById(\'copier-modal\');\n            const textarea = document.getElementById(\'copy-table-data\');\n            \n            // Biến mảng thành định dạng phân tách bằng tab (\\t) để paste trực tiếp vào Excel/Sheets\n            const formattedRow = rowData.join(\'\\t\');\n            \n            textarea.value = formattedRow;\n            modal.style.display = \'flex\';\n        }\n\n        function closeCopierModal() {\n            document.getElementById(\'copier-modal\').style.display = \'none\';\n        }\n\n        function copyRowToClipboard() {\n            const textarea = document.getElementById(\'copy-table-data\');\n            textarea.select();\n            document.execCommand(\'copy\');\n            showBannerNotification(\'📋 Đã sao chép dòng dữ liệu! Giờ bạn chỉ cần bôi đen dòng trống ở Google Sheets và nhấn Ctrl + V.\', \'green\');\n            closeCopierModal();\n        }\n\n        // ==========================================\n        // UI HELPERS\n        // ==========================================\n        function switchTab(tabId) {\n            document.querySelectorAll(\'.mode-tab\').forEach(tab => {\n                tab.classList.remove(\'active\');\n                if (tab.getAttribute(\'data-tab\') === tabId) tab.classList.add(\'active\');\n            });\n\n            document.querySelectorAll(\'.content-section\').forEach(sec => {\n                sec.classList.remove(\'active\');\n            });\n            document.getElementById(tabId).classList.add(\'active\');\n\n            if (tabId === \'history-tab\') {\n                loadCrawlSessions();\n            }\n        }\n\n        function loadCrawlSessions() {\n            const tableBody = document.getElementById(\'sessions-table-body\');\n            if (!tableBody) return;\n\n            tableBody.innerHTML = `<tr><td colspan="6" style="padding: 20px; text-align: center; color: var(--text-muted);">Đang tải lịch sử cào...</td></tr>`;\n\n            fetch(\'/api/crawl/sessions\')\n                .then(res => res.json())\n                .then(data => {\n                    // Cập nhật các thẻ metrics\n                    const totals = data.totals || {};\n                    document.getElementById(\'total-sessions-val\').innerText = totals.total_sessions || 0;\n                    document.getElementById(\'total-crawled-val\').innerText = totals.total_crawled || 0;\n                    \n                    // Format tổng thời gian cào\n                    const totalDurSec = totals.total_duration || 0;\n                    if (totalDurSec >= 3600) {\n                        const h = Math.floor(totalDurSec / 3600);\n                        const m = Math.floor((totalDurSec % 3600) / 60);\n                        document.getElementById(\'total-duration-val\').innerText = `${h} giờ ${m} phút`;\n                    } else if (totalDurSec >= 60) {\n                        const m = Math.floor(totalDurSec / 60);\n                        const s = Math.floor(totalDurSec % 60);\n                        document.getElementById(\'total-duration-val\').innerText = `${m} phút ${s} giây`;\n                    } else {\n                        document.getElementById(\'total-duration-val\').innerText = `${Math.floor(totalDurSec)} giây`;\n                    }\n                    \n                    document.getElementById(\'overall-speed-val\').innerText = totals.overall_avg_speed || \'N/A\';\n\n                    // Cập nhật bảng\n                    const sessions = data.sessions || [];\n                    if (sessions.length === 0) {\n                        tableBody.innerHTML = `<tr><td colspan="6" style="padding: 20px; text-align: center; color: var(--text-muted);">Chưa có phiên cào nào được ghi nhận.</td></tr>`;\n                        return;\n                    }\n\n                    tableBody.innerHTML = \'\';\n                    sessions.forEach(sess => {\n                        const startTime = sess.start_time ? new Date(sess.start_time).toLocaleString(\'vi-VN\') : \'N/A\';\n                        \n                        // Định dạng thời lượng\n                        const dur = sess.duration || 0;\n                        let durStr = \'\';\n                        if (dur >= 60) {\n                            durStr = `${Math.floor(dur / 60)} phút ${Math.floor(dur % 60)} giây`;\n                        } else {\n                            durStr = `${Math.floor(dur)} giây`;\n                        }\n\n                        // Định dạng tốc độ\n                        const count = sess.crawled_count || 0;\n                        const speedStr = count > 0 ? `${(dur / count).toFixed(1)} giây/căn` : \'N/A\';\n\n                        // Định dạng trạng thái badge\n                        let badgeHtml = \'\';\n                        const status = sess.status || \'stopped\';\n                        if (status === \'completed\') {\n                            badgeHtml = `<span style="background: rgba(16, 185, 129, 0.15); border: 1px solid var(--text-green); color: var(--text-green); padding: 2px 6px; border-radius: 4px; font-size: 10px;">Thành công</span>`;\n                        } else if (status === \'limit_reached\') {\n                            badgeHtml = `<span style="background: rgba(59, 130, 246, 0.15); border: 1px solid var(--accent-cyan); color: var(--accent-cyan); padding: 2px 6px; border-radius: 4px; font-size: 10px;">Đạt giới hạn</span>`;\n                        } else if (status === \'cookie_expired\') {\n                            badgeHtml = `<span style="background: rgba(239, 68, 68, 0.15); border: 1px solid var(--accent-red); color: var(--accent-red); padding: 2px 6px; border-radius: 4px; font-size: 10px;">Hết hạn Cookie</span>`;\n                        } else {\n                            badgeHtml = `<span style="background: rgba(251, 191, 36, 0.15); border: 1px solid var(--accent-gold); color: var(--accent-gold); padding: 2px 6px; border-radius: 4px; font-size: 10px;">Đã ngắt</span>`;\n                        }\n\n                        const tr = document.createElement(\'tr\');\n                        tr.style.borderBottom = \'1px solid rgba(255,255,255,0.05)\';\n                        tr.innerHTML = `\n                            <td style="padding: 10px 15px;">${startTime}</td>\n                            <td style="padding: 10px 15px; font-family: monospace; color: var(--text-muted);">${sess.cookie_sig || \'N/A\'}</td>\n                            <td style="padding: 10px 15px;">${durStr}</td>\n                            <td style="padding: 10px 15px; font-weight: bold; color: var(--accent-gold);">${count}</td>\n                            <td style="padding: 10px 15px;">${speedStr}</td>\n                            <td style="padding: 10px 15px;">${badgeHtml}</td>\n                        `;\n                        tableBody.appendChild(tr);\n                    });\n                })\n                .catch(err => {\n                    tableBody.innerHTML = `<tr><td colspan="6" style="padding: 20px; text-align: center; color: var(--accent-red);">Lỗi tải lịch sử: ${err}</td></tr>`;\n                });\n        }\n\n        function showToast(message, type = \'success\') {\n            const container = document.getElementById(\'toast-container\');\n            if (!container) return;\n            \n            const toast = document.createElement(\'div\');\n            toast.className = `toast-item toast-${type}`;\n            \n            let icon = \'💡\';\n            if (type === \'success\') icon = \'✅\';\n            else if (type === \'warning\') icon = \'⚠️\';\n            else if (type === \'error\') icon = \'❌\';\n            \n            toast.innerHTML = `<span style="font-size: 18px;">${icon}</span> <span>${message}</span>`;\n            container.appendChild(toast);\n            \n            // Kích hoạt animation slide-in\n            setTimeout(() => {\n                toast.classList.add(\'show\');\n            }, 50);\n            \n            // Tự động ẩn sau 4 giây\n            setTimeout(() => {\n                toast.classList.remove(\'show\');\n                setTimeout(() => {\n                    toast.remove();\n                }, 400);\n            }, 4000);\n        }\n\n        function showBannerNotification(message, colorClass) {\n            // 1. Ghi log vào Terminal\n            let color = \'var(--accent-gold)\';\n            let type = \'warning\';\n            \n            if (colorClass === \'green\') {\n                color = \'var(--accent-green)\';\n                type = \'success\';\n            } else if (colorClass === \'red\') {\n                color = \'var(--accent-red)\';\n                type = \'error\';\n            } else if (colorClass === \'yellow\' || colorClass === \'gold\') {\n                color = \'var(--accent-gold)\';\n                type = \'warning\';\n            }\n            \n            addLogConsoleLine(`*** ${message.toUpperCase()} ***`, color);\n            \n            // 2. Kích hoạt Toast hiển thị nổi bật trực quan trên màn hình\n            showToast(message, type);\n        }\n\n        function addLogConsoleLine(text, color) {\n            const term = document.getElementById(\'terminal-log\');\n            const timestamp = new Date().toLocaleTimeString();\n            term.innerHTML += `<div class="terminal-line" style="color: ${color}; font-weight: bold;">[${timestamp}] ${escapeHtml(text)}</div>`;\n            term.scrollTop = term.scrollHeight;\n        }\n\n        function escapeHtml(text) {\n            return text\n                .replace(/&/g, "&amp;")\n                .replace(/</g, "&lt;")\n                .replace(/>/g, "&gt;")\n                .replace(/"/g, "&quot;")\n                .replace(/\'/g, "&#039;");\n        }\n        // ==================================================\n        // US-100 DYNAMIC FILTERS & TROUBLESHOOTING JS (US-100)\n        // ==================================================\n        let currentFiltersConfig = [];\n\n        function renderDynamicFiltersTable() {\n            const container = document.getElementById(\'dynamic-filters-list\');\n            if (!container) return;\n            \n            if (currentFiltersConfig.length === 0) {\n                container.innerHTML = `<div style="text-align: center; padding: 15px; font-size: 11px; color: var(--text-muted); background: rgba(0,0,0,0.1); border-radius: 6px; border: 1px dashed var(--border-color);">Chưa cấu hình bộ lọc động nào. Hãy thêm bộ lọc mới ở form bên dưới.</div>`;\n                return;\n            }\n            \n            let html = `\n                <table style="width: 100%; border-collapse: collapse; font-size: 11px; text-align: left; background: rgba(0,0,0,0.1); border-radius: 6px; border: 1px solid var(--border-color); overflow: hidden;">\n                    <thead>\n                        <tr style="background: rgba(255,255,255,0.02); border-bottom: 1px solid var(--border-color);">\n                            <th style="padding: 8px;">Nhãn hiển thị</th>\n                            <th style="padding: 8px;">Khóa dữ liệu (Key)</th>\n                            <th style="padding: 8px;">Loại</th>\n                            <th style="padding: 8px;">Tùy chọn (Options)</th>\n                            <th style="padding: 8px; text-align: right;">Xóa</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n            `;\n            \n            currentFiltersConfig.forEach((f, idx) => {\n                const optionsStr = f.options ? f.options.filter(x => x).join(\', \') : \'\';\n                html += `\n                    <tr style="border-bottom: 1px solid rgba(255,255,255,0.05);">\n                        <td style="padding: 8px; font-weight: bold; color: var(--accent-gold);">${escapeHtml(f.label)}</td>\n                        <td style="padding: 8px; font-family: monospace; color: var(--text-muted);">${escapeHtml(f.field)}</td>\n                        <td style="padding: 8px;"><span style="background: rgba(59, 130, 246, 0.1); color: #60a5fa; padding: 2px 6px; border-radius: 4px; font-size: 9px;">${f.type === \'select\' ? \'Select\' : \'Text\'}</span></td>\n                        <td style="padding: 8px; max-width: 150px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${escapeHtml(optionsStr)}">${escapeHtml(optionsStr) || \'<i style="color:var(--text-muted)">Không có</i>\'}</td>\n                        <td style="padding: 8px; text-align: right;">\n                            <button onclick="deleteDynamicFilter(${idx})" style="background: transparent; border: none; color: var(--accent-red); cursor: pointer; font-size: 14px; padding: 2px 6px;" title="Xóa bộ lọc này">🗑️</button>\n                        </td>\n                    </tr>\n                `;\n            });\n            \n            html += `\n                    </tbody>\n                </table>\n            `;\n            container.innerHTML = html;\n        }\n\n        function addNewDynamicFilter() {\n            const fieldInput = document.getElementById(\'new-filter-field\');\n            const labelInput = document.getElementById(\'new-filter-label\');\n            const typeInput = document.getElementById(\'new-filter-type\');\n            const optionsInput = document.getElementById(\'new-filter-options\');\n            \n            const field = fieldInput.value.trim();\n            const label = labelInput.value.trim();\n            const type = typeInput.value;\n            let options = [];\n            \n            if (!field || !label) {\n                alert("Vui lòng nhập đầy đủ Khóa dữ liệu và Nhãn hiển thị!");\n                return;\n            }\n            \n            if (type === \'select\') {\n                const optVal = optionsInput.value.trim();\n                if (optVal) {\n                    options = optVal.split(\',\').map(o => o.trim());\n                    // Đảm bảo có tùy chọn rỗng ở đầu nếu chưa có\n                    if (options.length > 0 && options[0] !== \'\') {\n                        options.unshift(\'\');\n                    }\n                } else {\n                    options = [\'\'];\n                }\n            }\n            \n            // Kiểm tra trùng lặp\n            if (currentFiltersConfig.some(f => f.field === field)) {\n                alert("Khóa dữ liệu này đã tồn tại trong cấu hình!");\n                return;\n            }\n            \n            currentFiltersConfig.push({ field, label, type, options });\n            renderDynamicFiltersTable();\n            saveDynamicFiltersConfig();\n            \n            // Reset inputs\n            fieldInput.value = \'\';\n            labelInput.value = \'\';\n            optionsInput.value = \'\';\n        }\n\n        function deleteDynamicFilter(idx) {\n            if (!confirm("Bạn có chắc muốn xóa bộ lọc này khỏi cấu hình?")) return;\n            currentFiltersConfig.splice(idx, 1);\n            renderDynamicFiltersTable();\n            saveDynamicFiltersConfig();\n        }\n\n        function saveDynamicFiltersConfig() {\n            // Lấy config hiện tại trước để merge\n            fetch(\'/api/config\')\n                .then(res => res.json())\n                .then(data => {\n                    if (data.status === \'success\') {\n                        const cfg = data.config;\n                        // Chỉ cập nhật thuộc tính json_ui_filters và gửi POST\n                        cfg.json_ui_filters = currentFiltersConfig;\n                        \n                        fetch(\'/api/config\', {\n                            method: \'POST\',\n                            headers: { \'Content-Type\': \'application/json\' },\n                            body: JSON.stringify(cfg)\n                        })\n                        .then(res => res.json())\n                        .then(resData => {\n                            if (resData.status === \'success\') {\n                                showBannerNotification(\'⚙️ Đã lưu cấu hình bộ lọc động thành công!\', \'green\');\n                            }\n                        });\n                    }\n                });\n        }\n\n        function triggerSyncJsonUi() {\n            showBannerNotification(\'⏳ Đang kích hoạt tiến trình đồng bộ JSON UI hàng loạt...\', \'gold\');\n            fetch(\'/api/sync-json-ui\', {\n                method: \'POST\',\n                headers: { \'Content-Type\': \'application/json\' },\n                body: JSON.stringify({})\n            })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(\'🔄 Tiến trình đồng bộ JSON UI đã chạy ngầm thành công. Theo dõi log ở console bên dưới.\', \'green\');\n                } else {\n                    alert(\'Lỗi kích hoạt đồng bộ: \' + data.message);\n                }\n            })\n            .catch(err => {\n                alert(\'Lỗi kết nối máy chủ khi đồng bộ: \' + err);\n            });\n        }\n\n        function loadTroubleList() {\n            const tbody = document.getElementById(\'trouble-table-body\');\n            if (!tbody) return;\n            \n            fetch(\'/api/listings?status=crawl_failed\')\n                .then(res => res.json())\n                .then(data => {\n                    tbody.innerHTML = \'\';\n                    const listings = data.listings || [];\n                    if (listings.length === 0) {\n                        tbody.innerHTML = `<tr><td colspan="3" style="text-align: center; padding: 20px; color: var(--text-muted); font-style: italic;">🎉 Tuyệt vời! Không phát hiện căn nào bị lỗi cào thô.</td></tr>`;\n                        return;\n                    }\n                    \n                    listings.forEach(item => {\n                        let reasonText = "Lỗi chưa xác định";\n                        const status = item.status || "";\n                        if (status.includes("deleted")) {\n                            reasonText = "❌ Đã xóa/Không tìm thấy trên nguồn";\n                        } else if (status.includes("cookie_expired")) {\n                            reasonText = "🔑 Cookie hết hạn / Hết phiên";\n                        } else if (status.includes("http_error")) {\n                            reasonText = "🌐 Lỗi HTTP / Mạng kết nối";\n                        } else if (status.includes("exception")) {\n                            reasonText = "⚠️ Lỗi xử lý dữ liệu (Exception)";\n                        } else if (status.includes("cookie_invalid")) {\n                            reasonText = "🔑 Cookie không hợp lệ";\n                        }\n                        \n                        tbody.innerHTML += `\n                            <tr style="border-bottom: 1px solid rgba(255,255,255,0.03); hover: background-color: rgba(255,255,255,0.01);">\n                                <td style="padding: 8px; font-weight: bold; font-family: monospace;">${escapeHtml(item.tk_id)}</td>\n                                <td style="padding: 8px; color: #f87171;">${escapeHtml(reasonText)}</td>\n                                <td style="padding: 8px; text-align: right; display: flex; justify-content: flex-end; gap: 8px;">\n                                    <button class="btn" onclick="recrawlTroubleListing(\'${item.tk_id}\', this)" style="font-size: 9px; padding: 2px 6px; height: auto; background: rgba(59, 130, 246, 0.2); border: 1px solid #3b82f6; color: #60a5fa;" title="Thử cào lại căn này">🔄 Cào lại</button>\n                                    <button class="btn" onclick="deleteTroubleListing(\'${item.tk_id}\', this)" style="font-size: 9px; padding: 2px 6px; height: auto; background: rgba(239, 68, 68, 0.2); border: 1px solid #ef4444; color: #f87171;" title="Xóa căn này khỏi DB">🗑️ Xóa</button>\n                                </td>\n                            </tr>\n                        `;\n                    });\n                })\n                .catch(err => {\n                    console.error("Error loading troubleshooting list:", err);\n                });\n        }\n\n        function recrawlTroubleListing(tkId, btn) {\n            btn.disabled = true;\n            btn.innerText = "⏳...";\n            showBannerNotification(`⏳ Bắt đầu cào lại căn [${tkId}]...`, \'gold\');\n            \n            fetch(`/api/listings/${tkId}/recrawl`, { method: \'POST\' })\n            .then(res => res.json())\n            .then(data => {\n                btn.disabled = false;\n                btn.innerText = "🔄 Cào lại";\n                if (data.status === \'success\') {\n                    showBannerNotification(`🎉 Cào lại thành công căn [${tkId}]!`, \'green\');\n                    loadTroubleList();\n                    fetchListings();\n                } else {\n                    alert(\'Không thể cào lại: \' + data.message);\n                    loadTroubleList();\n                    fetchListings();\n                }\n            })\n            .catch(err => {\n                btn.disabled = false;\n                btn.innerText = "🔄 Cào lại";\n                alert(\'Lỗi kết nối khi cào lại: \' + err);\n                loadTroubleList();\n                fetchListings();\n            });\n        }\n\n        function deleteTroubleListing(tkId, btn) {\n            if (!confirm(`Bạn có chắc chắn muốn xóa vĩnh viễn căn [${tkId}] khỏi database cục bộ?`)) return;\n            \n            btn.disabled = true;\n            fetch(`/api/listings/${tkId}`, { method: \'DELETE\' })\n            .then(res => res.json())\n            .then(data => {\n                if (data.status === \'success\') {\n                    showBannerNotification(`🗑️ Đã xóa thành công căn [${tkId}] khỏi database!`, \'green\');\n                    loadTroubleList();\n                    fetchListings();\n                } else {\n                    btn.disabled = false;\n                    alert(\'Lỗi khi xóa: \' + data.message);\n                }\n            })\n            .catch(err => {\n                btn.disabled = false;\n                alert(\'Lỗi kết nối khi xóa: \' + err);\n            });\n        }\n    </script>\n</body>\n</html>\n'
